module priority_encoder_8x3 (
    input       [7:0] in      ,   // 8 input lines
    output reg  [2:0] out         // 3 output lines
);

always @(*) begin
    if (in[7])
        out = 3'b111;
    else if (in[6])
        out = 3'b110;
    else if (in[5])
        out = 3'b101;
    else if (in[4])
        out = 3'b100;
    else if (in[3])
        out = 3'b011;
    else if (in[2])
        out = 3'b010;
    else if (in[1])
        out = 3'b001;
    else if (in[0])
        out = 3'b000;
    else
        out = 3'b000; // Default case when no inputs are active
end

endmodule

output.rtl/cascaded_encoder.v:
module priority_encoder (
    input  [N-1:0] in,
    output reg [M-1:0] out
);
    parameter N, M = log2(N);
    reg [M-1:0] result;
begin
    for (i = N-1; i >= 0; i = i-1) begin
        if (in[i]) begin
            result = (i+1)[M-1:0];
            break;
        end
    end
    out = result;
endmodule

module cascaded_encoder (
    input  [N-1:0] in,
    output reg [M-1:0] out,
    output reg [M-2:0] out_upper_half,
    output reg [M-2:0] out_lower_half
);
    parameter N, M = log2(N);
    wire [M-1:0] upper_half, lower_half;
    priority_encoder pe_upper (
        input  upper_half,
        output reg out_upper_half
    );
    priority_encoder pe_lower (
        input  lower_half,
        output reg out_lower_half
    );
begin
    upper_half = [N/2-1:0] in;
    lower_half = [N/2:0] in;

    if (out_upper_half != 0) begin
        out = out_upper_half;
    else begin
        out = out_lower_half;
    end
    out = out_upper_half | (out_lower_half << 1);
endmodule

output.rtl/Attenuator.sv:
module Attenuator (
    input        clk,
    input        reset,
    input  [4:0] data,
    output reg   ATTN_CLK,
    output reg   ATTN_DATA,
    output reg   ATTN_LE
);

// Internal Signals
reg        clk_div2;
reg  [1:0] current_state, next_state;
reg  [4:0] shift_reg;
reg  [2:0] bit_count;
reg  [4:0] old_data;

// Parameters for FSM States
localparam IDLE  = 2'b00,
           LOAD  = 2'b01,
           SHIFT = 2'b10,
           LATCH = 2'b11;

// Reset Condition
always @(posedge clk or posedge reset) begin
    if (reset) begin
        clk_div2 <= 1'b0;
        current_state <= IDLE;
        ATTN_CLK      <= 1'b0;
        ATTN_DATA     <= 1'b0;
        ATTN_LE       <= 1'b0;
        shift_reg     <= 5'b00000;
        bit_count     <= 3'd0;
        old_data      <= 5'b00000;
    else begin
        if (data != old_data) begin
            current_state <= LOAD;
        end else begin
            // No data change, stay in current state
        end
    end
end else if (current_state == SHIFT) begin
    ATTN_DATA <= shift_reg[0];
    shift_reg <= (shift_reg >> 1);
    bit_count <= bit_count + 1;
    next_state <= LATCH;
end else if (current_state == LATCH) begin
    ATTN_LE <= 1;
    bit_count <= 0;
    next_state <= IDLE;
end

// FSM State Transitions
always @* begin
    case (current_state)
        IDLE:
            if (data != old_data)
                current_state = LOAD;
            next_state = current_state;
        LOAD:
            shift_reg = data;
            current_state = LOAD;
            next_state = current_state;
        SHIFT:
            ATTN_DATA <= shift_reg[0];
            shift_reg <= shift_reg >> 1;
            bit_count <= bit_count + 1;
            if (bit_count == 5)
                current_state = LATCH;
            next_state = current_state;
        LATCH:
            ATTN_LE <= 1;
            next_state = IDLE;
    endcase
end

// Internal State Variables
always @* begin
    old_data <= data;
    bit_count <= bit_count + 1;
end

