output.rtl/sync_muller_c_element.sv:
module sync_muller_c_element #(
  parameter NUM_INPUT  = 2,
  parameter PIPE_DEPTH = 1
) (
  input  logic                  clk,
  input  logic                  srst,
  input  logic                  clr,
  input  logic                  clk_en,
  input  logic  [NUM_INPUT-1:0] inp,
  output logic                  out
);

  logic [(PIPE_DEPTH*NUM_INPUT)-1:0] pipe;
  genvar i;

  generate
    // Initialize pipeline with input values
    assign pipe[0*NUM_INPUT + 0] = inp[0];
    assign pipe[0*NUM_INPUT + 1] = inp[1];

    // Propagate through pipeline stages
    for (i = 1; i < PIPE_DEPTH; i++) begin
      assign pipe[i*NUM_INPUT + 0] = pipe[(i-1)*NUM_INPUT + 0];
      assign pipe[i*NUM_INPUT + 1] = pipe[(i-1)*NUM_INPUT + 1];
    end
  endgenerate

  // Compute output based on final pipeline stage
  assign out = 1;
  for (i = 0; i < NUM_INPUT; i++) begin
    if (pipe[PIPE_DEPTH*NUM_INPUT - 1 + i] != 1)
      out = 0;
    else
      out = 1;
  end
  if (out == 0 && !clk_en) out = 0;

  // Reset pipeline and output
  always begin
    if (srst || clr) begin
      pipe = 0;
      out = 0;
    end
  end

endmodule

output.rtl/adc_data_rotate.sv:
module adc_data_rotate #(
    parameter DATA_WIDTH = 8
)(
    input logic i_clk,
    input logic i_rst_n,
    input logic [DATA_WIDTH-1:0] i_adc_data_in,
    input logic [3:0] i_shift_count,
    input logic i_shift_direction,
    output logic [DATA_WIDTH-1:0] o_processed_data,
    output logic o_operation_status
);

    wire [DATA_WIDTH-1:0] rotated_data;

    always_comb if (i_rst_n) begin
        o_processed_data = 0;
        o_operation_status = 0;
    end

    clocked process (i_clk) begin
        if (i_rst_n) begin
            o_operation_status = 0;
            return;
        end

        integer effective_shift = i_shift_count % DATA_WIDTH;
        if (effective_shift == 0) begin
            o_processed_data = i_adc_data_in;
            o_operation_status = 1;
            return;
        end

        if (i_shift_direction) begin // Right rotate
            rotated_data = (i_adc_data_in >> effective_shift) | (i_adc_data_in << (DATA_WIDTH - effective_shift));
        else begin // Left rotate
            rotated_data = (i_adc_data_in << effective_shift) | (i_adc_data_in >> (DATA_WIDTH - effective_shift));
        end

        o_processed_data = rotated_data;
        o_operation_status = 1;
    end

endmodule

