module axi_alu (
    input  wire        axi_clk_in,
    input  wire        fast_clk_in,
    input  wire        reset_in,

    // AXI Interface
    input  wire        axi_awvalid_i,
    input  wire        axi_wvalid_i,
    input  wire        axi_bready_i,
    input  wire        axi_arvalid_i,
    input  wire        axi_rready_i,

    output wire        axi_awready_o,
    output wire        axi_wready_o,
    output wire        axi_bvalid_o,
    output wire        axi_arready_o,
    output wire        axi_rvalid_o,

    input  wire [31:0] axi_awaddr_i,
    input  wire [31:0] axi_wdata_i,
    input  wire [31:0] axi_araddr_i,

    input  wire [3:0]  axi_wstrb_i,
    output wire [31:0] axi_rdata_o,
    output wire [63:0] result_o
);

    wire        clk;
    wire [31:0] operand_a, operand_b, operand_c;
    wire [1:0]  op_select;
    wire        start, clock_control;
    wire [31:0] data_a;
    wire [31:0] data_b;
    wire [31:0] data_c;

    wire [31:0] operand_a_cdc, operand_b_cdc, operand_c_cdc;
    wire [1:0]  op_select_cdc;
    wire        start_cdc;
    wire [31:0] operand_a_sync, operand_b_sync, operand_c_sync;
    wire [1:0]  op_select_sync;
    wire        start_sync;

    clock_control u_clock_control (
        .axi_clk_in  (axi_clk_in),
        .fast_clk_in (fast_clk_in),
        .clk_ctrl    (clock_control),
        .clk         (clk)
    );

    axi_csr_block u_axi_csr_block (
        .axi_aclk_i    (axi_clk_in),
        .axi_areset_i  (reset_in),
        .axi_awvalid_i   (axi_awvalid_i),
        .axi_awready_o   (axi_awready_o),
        .axi_awaddr_i    (axi_awaddr_i),
        .axi_wvalid_i    (axi_wvalid_i),
        .axi_wready_o    (axi_wready_o),
        .axi_wdata_i     (axi_wdata_i),
        .axi_wstrb_i     (axi_wstrb_i),
        .axi_bvalid_o    (axi_bvalid_o),
        .axi_bready_i    (axi_bready_i),
        .axi_arvalid_i   (axi_arvalid_i),
        .axi_arready_o   (axi_arready_o),
        .axi_araddr_i    (axi_araddr_i),
        .axi_rvalid_o    (axi_rvalid_o),
        .axi_rready_i    (axi_rready_i),
        .axi_rdata_o     (axi_rdata_o),
        .operand_a     (operand_a_cdc),
        .operand_b     (operand_b_cdc),
        .operand_c     (operand_c_cdc),
        .op_select     (op_select_cdc),
        .start         (start_cdc),
        .clock_control (clock_control)
    );

    // CDC logic is only active when clock_control is HIGH
    assign operand_a = (clock_control) ? operand_a_sync : operand_a_cdc;
    assign operand_b = (clock_control) ? operand_b_sync : operand_b_cdc;
    assign operand_c = (clock_control) ? operand_c_sync : operand_c_cdc;
    assign op_select = (clock_control) ? op_select_sync : op_select_cdc;
    assign start     = (clock_control) ? start_sync : start_cdc;

    // CDC Synchronizers (only used when fast_clk is selected)
    cdc_synchronizer #(.WIDTH(32)) u_cdc_operand_a (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(operand_a_cdc), .data_out(operand_a_sync));
    cdc_synchronizer #(.WIDTH(32)) u_cdc_operand_b (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(operand_b_cdc), .data_out(operand_b_sync));
    cdc_synchronizer #(.WIDTH(32)) u_cdc_operand_c (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(operand_c_cdc), .data_out(operand_c_sync));
    cdc_synchronizer #(.WIDTH(2))  u_cdc_op_select  (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(op_select_cdc), .data_out(op_select_sync));
    cdc_synchronizer #(.WIDTH(1))  u_cdc_start      (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(start_cdc), .data_out(start_sync));

    memory_block u_memory_block (
        .clk        (clk),
        .reset_in   (reset_in),
        .address_a  (operand_a[5:0]),
        .address_b  (operand_b[5:0]),
        .address_c  (operand_c[5:0]),
        .data_a     (data_a),
        .data_b     (data_b),
        .data_c     (data_c)
    );

    dsp_block u_dsp_block (
        .clk        (clk),
        .reset_in   (reset_in),
        .operand_a  (data_a),
        .operand_b  (data_b),
        .operand_c  (data_c),
        .op_select  (op_select),
        .start      (start),
        .result     (result_o)
    );

endmodule

// ------------------------------------------------------------------
// CDC Synchronizer Module (Double Flop Synchronization)
// ------------------------------------------------------------------
module cdc_synchronizer #(parameter WIDTH = 1) (
    input wire clk_src,  // Source clock
    input wire clk_dst,  // Destination clock
    input wire reset_in, // Reset signal
    input wire [WIDTH-1:0] data_in,  // Data from source domain
    output reg [WIDTH-1:0] data_out  // Synchronized data in destination domain
);
    reg [WIDTH-1:0] data_sync_1, data_sync_2;

    always @(posedge clk_dst or posedge reset_in) begin
        if (reset_in) begin
            data_sync_1 <= {WIDTH{1'b0}};
            data_sync_2 <= {WIDTH{1'b0}};
            data_out    <= {WIDTH{1'b0}};
        end else begin
            data_sync_1 <= data_in;   // First stage
            data_sync_2 <= data_sync_1; // Second stage
            data_out    <= data_sync_2; // Stable output
        end
    end
endmodule

// ------------------------------------------------------------------
// Clock Control Module
// ------------------------------------------------------------------
module clock_control (
    input  wire axi_clk_in,
    input  wire fast_clk_in,
    input  wire clk_ctrl,
    output wire clk
);
    assign clk = clk_ctrl ? fast_clk_in : axi_clk_in;
endmodule

// ------------------------------------------------------------------
// AXI-to-CSR Register Block (With Write Response Handling)
// ------------------------------------------------------------------
module axi_csr_block (
    input  wire        axi_aclk_i,
    input  wire        axi_areset_i,

    // AXI Write Address Channel
    input  wire        axi_awvalid_i,
    output reg         axi_awready_o,
    input  wire [31:0] axi_awaddr_i,

    // AXI Write Data Channel
    input  wire        axi_wvalid_i,
    output reg         axi_wready_o,
    input  wire [31:0] axi_wdata_i,
    input  wire [3:0]  axi_wstrb_i,

    // AXI Write Response Channel (FIXED)
    output reg         axi_bvalid_o,
    input  wire        axi_bready_i,

    // AXI Read Address Channel
    input  wire        axi_arvalid_i,
    output reg         axi_arready_o,
    input  wire [31:0] axi_araddr_i,

    // AXI Read Data Channel
    output reg         axi_rvalid_o,
    input  wire        axi_rready_i,
    output reg  [31:0] axi_rdata_o,

    // CSR Outputs
    output reg  [31:0] operand_a,
    output reg  [31:0] operand_b,
    output reg  [31:0] operand_c,
    output reg  [1:0]  op_select,
    output reg         start,
    output reg         clock_control
);
    reg [31:0] csr_reg [0:4];

    always @(posedge axi_aclk_i or posedge axi_areset_i) begin
        if (axi_areset_i) begin
            operand_a     <= 32'd0;
            operand_b     <= 32'd0;
            operand_c     <= 32'd0;
            op_select     <= 2'd0;
            start         <= 1'b0;
            clock_control <= 1'b0;
            axi_awready_o <= 0;
            axi_wready_o  <= 0;
            axi_bvalid_o  <= 0; // Set response valid
            axi_arready_o <= 0;
            axi_rvalid_o  <= 0;
            axi_rdata_o   <= 32'd0;
            csr_reg[0]    <= 32'd0;
            csr_reg[1]    <= 32'd0;
            csr_reg[2]    <= 32'd0;
            csr_reg[3]    <= 32'd0;
            csr_reg[4]    <= 32'd0;
        end else begin
            // Handle AXI Write
            if (axi_awvalid_i && axi_wvalid_i) begin
                csr_reg[axi_awaddr_i[4:2]] <= axi_wdata_i;
                axi_awready_o <= 1;
                axi_wready_o  <= 1;
                axi_bvalid_o  <= 1; // Set response valid
            end else begin
                axi_awready_o <= 0;
                axi_wready_o  <= 0;
                axi_bvalid_o  <= 0; // Set response valid
            end

            // Handle Write Response
            if (axi_bvalid_o && axi_bready_i) begin
                axi_bvalid_o <= 0; // Clear response once acknowledged
            end

            // Handle AXI Read
            if (axi_arvalid_i) begin
                axi_arready_o <= 1;
                axi_rvalid_o  <= 1;
                axi_rdata_o    <= csr_reg[axi_araddr_i[4:2]];
            end else begin
                axi_arready_o <= 0;
                axi_rvalid_o  <= 0;
            end

            // Update CSR Registers
            operand_a     <= csr_reg[0];
            operand_b     <= csr_reg[1];
            operand_c     <= csr_reg[2];
            op_select     <= csr_reg[3][1:0];
            start         <= csr_reg[3][2];
            clock_control <= csr_reg[4][0];
        end
    end
endmodule

// ------------------------------------------------------------------
// Memory Block (ROM)
// ------------------------------------------------------------------
module memory_block (
    input  wire        clk,
    input  wire        reset_in,
    input  wire [5:0]  address_a,
    input  wire [5:0]  address_b,
    input  wire [5:0]  address_c,
    output wire [31:0] data_a,
    output wire [31:0] data_b,
    output wire [31:0] data_c
);
    reg [31:0] rom [0:63];

    initial begin
        $readmemh("../rom_data.mem", rom);
    end

    assign data_a = (reset_in) ? 32'd0 : rom[address_a];
    assign data_b = (reset_in) ? 32'd0 : rom[address_b];
    assign data_c = (reset_in) ? 32'd0 : rom[address_c];
endmodule

// ------------------------------------------------------------------
// DSP Processing Block
// ------------------------------------------------------------------
module dsp_block (
    input  wire        clk,
    input  wire        reset_in,
    input  wire [31:0] operand_a,
    input  wire [31:0] operand_b,
    input  wire [31:0] operand_c,
    input  wire [1:0]  op_select,
    input  wire        start,
    output reg  [63:0] result
);
    always @(posedge clk or posedge reset_in) begin
        if (reset_in)
            result <= 64'd0;
        else begin
            if (start) begin
                case (op_select)
                    2'b00: result <= (operand_a + operand_b) * operand_c;    // MAC
                    2'b01: result <= operand_a * operand_b;    // Multiplication
                    2'b10: result <= operand_a >> operand_b[4:0]; // Shift Right
                    2'b11: result <= operand_b ? operand_a / operand_b : 64'hDEADDEAD; // Division (handle divide by zero)
                endcase
            end
        end
    end
endmodule

output.rtl/axi_register.sv:
module axi_register(
    parameter ADDR_WIDTH,
    parameter DATA_WIDTH,
    input clock_i,
    input rst_n_i,
    input [ADDR_WIDTH-1:0] awaddr_i,
    input [DATA_WIDTH-1:0] wdata_i,
    input [DATA_WIDTH/8-1:0] wstrb_i,
    input wvalid_i,
    input bready_i,
    input [ADDR_WIDTH-1:0] araddr_i,
    input arvalid_i,
    output arready_o,
    output [DATA_WIDTH-1:0] rdata_o,
    output rvalid_o,
    output [1:0] rresp_o,
    output [1:0] bresp_o,
    output beat_o,
    output start_o,
    output done_o,
    output writeback_o,
    output [31:0] id_reg
);

    // AXI handshake signals
    output arvalid_o;
    output arready_o;
    output awvalid_o;
    output awready_o;
    output bvalid_o;
    output bready_i;
    output wvalid_o;
    output wready_o;

    // Beat counter
    reg [19:0] beat_reg;

    // ID register
    reg [31:0] id_reg;

    // Start signal
    reg start_o;

    // Done status
    reg done_o;

    // Writeback signal
    reg writeback_o;

    // Address decoding
    reg [23:0] axi_address;

    // Beat address generator
    reg beat_addr;

    // AXI to module ports
    wire arvalid_o = arvalid_i;
    wire arready_o = arready_i;
    wire awvalid_o = awvalid_i;
    wire awready_o = awready_i;
    wire bvalid_o = bvalid_i;
    wire bready_i = bready_i;
    wire wvalid_o = wvalid_i;
    wire wready_o = wready_i;

    // Initialize registers
    always @* begin
        if (rst_n_i) begin
            beat_o = 0;
            start_o = 0;
            done_o = 0;
            writeback_o = 0;
            id_reg = 0x00010001;
        end
    end

    // Write transaction
    always @*+begin
        if (awvalid_i) begin
            awready_o = 1;
            // Address phase
            axi_address = [ADDR_WIDTH-1:0] awaddr_i;
            // Data phase
            if (wvalid_i) begin
                // Update beat counter
                beat_o = wdata_i;
                // Set start signal
                start_o = (wdata_i & 1) & wstrb_i[0];
                // Set done signal
                done_o = ~ (wdata_i & 1);
                // Set writeback signal
                writeback_o = (wdata_i & 1) & wstrb_i[0];
                // Update register
                beat_reg = wdata_i;
            end
            // Acknowledge write
            bresp_o = 2'b00;
            bvalid_o = 1;
        end
    end

    // Read transaction
    always @*+begin
        if (arvalid_i) begin
            arready_o = 1;
            // Address phase
            axi_address = [ADDR_WIDTH-1:0] araddr_i;
            // Data phase
            // Update beat counter
            beat_o = beat_reg;
            // Get done status
            done_o = arvalid_i & (beat_o & 1);
            // Read data
            rdata_o = (beat_reg < DATA_WIDTH) ? beat_reg[DATA_WIDTH-1:0] : 0;
            // Acknowledge read
            rresp_o = 2'b00;
            rvalid_o = 1;
        end
    end

    // Invalid address handling
    always @*+begin
        if (!arvalid_i && !awvalid_i) begin
            // Invalid address
            rresp_o = 2'b10;
        end
    end

    // Write to ID register
    always @*+begin
        if (wvalid_i && wstrb_i[0]) begin
            // Write to ID register
            id_reg = wdata_i;
            // Generate error
            bresp_o = 2'b10;
            bvalid_o = 1;
        end
    end
endmodule

output.rtl/axis_resize.sv:
module axis_resize (
  input clock,
  input resetn,
  input s_valid,
  input [15:0] s_data,
  output reg s_ready,
  input m_ready,
  output reg [7:0] m_data
);

  // FIFO buffer with depth 2
  fifo buffer [1] [8:0]fifo_data (
    input clock,
    input [7:0] data,
    output reg valid,
    output reg done
  );

  // Assign data to FIFO
  always @posedge clock begin
    if (m_ready) begin
      fifo_data Valid = 1;
      fifo_data Done = 0;
    end
  end

  // When reset is active, output is 0
  if (resetn) begin
    s_ready = 1;
    m_valid = 0;
    m_data = 8'b0;
    fifo_valid = 0;
    fifo_done = 1;
    return;
  end

  // Split data into two parts
  reg [7:0] d1, d2;
  d1 = s_data[15:8];
  d2 = s_data[7:0];

  // FIFO initialization
  fifo_valid = 0;
  fifo_done = 1;

  // Transfer data to master
  always @posedge clock begin
    if (m_ready) begin
      if (fifo_valid) begin
        m_data = (d1 << 8) | d2;
        fifo_valid = 0;
        fifo_done = 1;
      end
    end
  end

  // Update s_ready when master is ready
  s_ready = m_ready;

endmodule

output.rtl/axis_upscale.sv:
module axis_upscale(
    input clock,
    input resetn,
    input dfmt_enable,
    input dfmt_type,
    input dfmt_se,
    input s_axis_valid,
    input s_axis_data,
    output m_axis_ready,
    output m_axis_valid,
    output m_axis_data
);

    // Reset behavior
    if(resetn) begin
        m_axis_data = 0;
        m_axis_ready = 1;
        return;
    end

    // No data processing if reset is active
    if(!s_axis_valid) begin
        m_axis_data = 0;
        m_axis_ready = 1;
        return;
    end

    // No data format enabled
    if(!dfmt_enable) begin
        m_axis_data = s_axis_data << 8;
        m_axis_valid = 1;
        return;
    end

    // Apply data format type and sign extension
    wire (s_axis_data >> 23) as msb;
    wire extended_bit;

    if(dfmt_type == 0) begin
        extended_bit = msb;
    else begin
        extended_bit = ~msb;
    end

    if(dfmt_se) begin
        extended_bit = extended_bit & 1;
        extended_bit = extended_bit << 24;
    end

    m_axis_data = (extended_bit) | (s_axis_data << 24);
    m_axis_valid = 1;

endmodule

output.rtl/axi_tap.sv:
module axi_tap #(
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32
)(
    input           clk_i,
    input           rst_i,
    input           inport_awvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_awaddr_i,
    input           inport_awready_o,
    input           inport_wvalid_i,
    input  [DATA_WIDTH-1:0]   inport_wdata_i,
    input  [3:0]    inport_wstrb_i,
    input           inport_wready_o,
    input           inport_bready_i,
    input           inport_bvalid_i,
    output          inport_bresp_o,
    output [1:0]    inport_rresp_o,
    output          inport_arvalid_o,
    output          inport_arready_o,
    output          inport_rvalid_o,
    output  [DATA_WIDTH-1:0]   inport_rdata_o,
    output [1:0]    inport_rresp_o,
    output          outport_awvalid_o,
    output  [ADDR_WIDTH-1:0]   outport_awaddr_o,
    output          outport_wvalid_o,
    output  [DATA_WIDTH-1:0]   outport_wdata_o,
    output  [3:0]    outport_wstrb_o,
    output          outport_wready_o,
    output          outport_bvalid_o,
    output [1:0]    outport_bresp_o,
    output          outport_bready_o,
    output          outport_arvalid_o,
    output          outport_arready_o,
    output          outport_rvalid_o,
    output  [DATA_WIDTH-1:0]   outport_rdata_o,
    output [1:0]    outport_rresp_o
);

// Address decoding variables
reg [3:0]    address_mask = 32'h80000000;
reg [3:0]    peripheral_address = 32'h00000000;

// FIFO for out-of-order transactions
reg [3:0]    read_pending_q;
reg [3:0]    read_pending_r;
reg [`address_mask-1:0]  read_port_q;
reg [`address_mask-1:0]  read_port_r;

// Read channel FIFO
reg [3:0]    write_port_q;
reg [3:0]    write_port_r;
reg [3:0]    write_response_q;
reg [3:0]    write_response_r;

// Control signals
reg read_accept_w;
reg write_accept_w;
reg write_accept_r;
reg write_data_ready_q;
reg write_data_ready_r;

always @ (posedge clk_i)
begin
    if (rst_i) begin
        // Initialize FIFO
        read_pending_q <= 4'b0;
        read_port_q    <= `address_mask'b0;
        write_port_q    <= 4'b0;
        write_response_q <= 4'b0;
        write_data_ready_q <= 4'b0;
    end
    else begin
        // Update FIFO states
        read_pending_q <= read_pending_r;
        read_port_q    <= read_port_r;
        write_port_q    <= write_port_r;
        write_response_q <= write_response_r;
        write_data_ready_q <= write_data_ready_r;
    end
end

// Read channel logic
always @ (posedge clk_i)
begin
    if (rst_i) begin
        read_pending_q <= 4'b0;
        read_port_q    <= `address_mask'b0;
        write_port_q    <= 4'b0;
        write_response_q <= 4'b0;
        write_data_ready_q <= 4'b0;
    end
    else begin
        if (inport_arvalid_i && inport_arready_o) begin
            read_port_q <= read_port_r;
        end
        if (inport_rvalid_i && inport_rready_o && !write_data_ready_q) begin
            write_port_q <= write_port_r;
        end
    end
end

// Write channel logic
always @ (posedge clk_i)
begin
    if (rst_i) begin
        read_pending_q <= 4'b0;
        read_port_q    <= `address_mask'b0;
        write_port_q    <= 4'b0;
        write_response_q <= 4'b0;
        write_data_ready_q <= 4'b0;
    end
    else begin
        if (inport_awvalid_i && inport_awready_o) begin
            write_port_q <= write_port_r;
        end
        if (inport_wvalid_i && inport_wready_o && !read_data_ready_q) begin
            write_response_q <= write_response_r;
        end
    end
end

// Backpressure logic
always @ (posedge clk_i)
begin
    if (rst_i) begin
        read_accept_w <= 1'b0;
        write_accept_w <= 1'b0;
    end
    else begin
        read_accept_w <= (read_port_q == read_port_r && read_pending_q != 4'hF) || (read_pending_q == 4'h0);
        write_accept_w <= (write_port_q == write_port_r && write_data_ready_q != 4'hF) || (write_data_ready_q == 4'h0);
    end
end

// Response forwarding
always @ (posedge clk_i)
begin
    if (rst_i) begin
        outport_arvalid_o <= 1'b0;
        outport_arready_o <= 1'b0;
        outport_rvalid_o <= 1'b0;
        outport_rready_o <= 1'b0;
    end
    else begin
        case (write_port_q)
            `address_mask'd1:
                outport_arvalid_o <= inport_arvalid_i & read_accept_w & (read_port_r == `address_mask'd1);
                outport_arready_o <= inport_arready_i;
                outport_rvalid_o <= inport_rvalid_i;
                outport_rready_o <= inport_rready_i;
            default:
                outport_arvalid_o <= inport_arvalid_i & read_accept_w & (read_port_r == `address_mask'd0);
                outport_arready_o <= inport_arready_i;
                outport_rvalid_o <= inport_rvalid_i;
                outport_rready_o <= inport_rready_i;
        endcase
    end
end

// FIFO initialization
reg [3:0]    read_pending_init = 4'h0;
reg [3:0]    read_port_init = 4'h0;
reg [3:0]    write_port_init = 4'h0;
reg [3:0]    write_response_init = 4'h0;
reg [3:0]    write_data_ready_init = 4'h0;

always @ (posedge clk_i)
begin
    if (rst_i) begin
        read_pending_init <= 4'h0;
        read_port_init <= 4'h0;
        write_port_init <= 4'h0;
        write_response_init <= 4'h0;
        write_data_ready_init <= 4'h0;
    end
    else begin
        read_pending_q <= read_pending_init;
        read_port_q    <= read_port_init;
        write_port_q    <= write_port_init;
        write_response_q <= write_response_init;
        write_data_ready_q <= write_data_ready_init;
    end
end

// Final cleanup
always @ (posedgeclk_i)
begin
    if (rst_i) begin
        read_port_init <= 4'h0;
        write_port_init <= 4'h0;
        write_response_init <= 4'h0;
        write_data_ready_init <= 4'h0;
    end
end

// Module ports
module axi peripheral0 (
    input           clk_i,
    input           rst_i,
    input           inport_awvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_awaddr_i,
    input           inport_awready_o,
    input           inport_wvalid_i,
    input  [DATA_WIDTH-1:0]   inport_wdata_i,
    input  [3:0]    inport_wstrb_i,
    input           inport_wready_o,
    input           inport_bready_i,
    input           inport_bvalid_i,
    output          inport_bresp_o,
    output [1:0]    inport_rresp_o,
    output          inport_arvalid_o,
    output          inport_arready_o,
    output          inport_rvalid_o,
    output  [DATA_WIDTH-1:0]   inport_rdata_o,
    output [1:0]    inport_rresp_o,
    output          outport_awvalid_o,
    output  [ADDR_WIDTH-1:0]   outport_awaddr_o,
    output          outport_wvalid_o,
    output  [DATA_WIDTH-1:0]   outport_wdata_o,
    output  [3:0]    outport_wstrb_o,
    output          outport_wready_o,
    output          outport_bvalid_o,
    output [1:0]    outport_bresp_o,
    output          outport_bready_o,
    output          outport_arvalid_o,
    output          outport_arready_o,
    output          outport_rvalid_o,
    output  [DATA_WIDTH-1:0]   outport_rdata_o,
    output [1:0]    outport_rresp_o
);

// Initialize FIFO
initial begin
    read_port_init = 4'h0;
    write_port_init = 4'h0;
    write_response_init = 4'h0;
    write_data_ready_init = 4'h0;
end

input.rtl/axi_tap.sv:
module axi_tap #(
    parameter ADDR_WIDTH = 32, // Width of AXI4-Lite Address
    parameter DATA_WIDTH = 32  // Width of AXI4-Lite Data
)(
    // Global Ports
    input           clk_i,
    input           rst_i,

    // Master Write Address Channel (AW)
    input           inport_awvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_awaddr_i,
    output          inport_awready_o,
    // Master Write Data Channel (W)
    input           inport_wvalid_i,
    input  [DATA_WIDTH-1:0]   inport_wdata_i,
    input  [3:0]    inport_wstrb_i,
    output          inport_wready_o,
    // Master Write Response Channel (B)
    input           inport_bready_i,
    output          inport_bvalid_o,
    output [1:0]    inport_bresp_o,
    // Master Read Address Channel (AR)
    input           inport_arvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_araddr_i,
    output          inport_arready_o,
    // Master Read Data Channel (R)
    input           inport_rready_i,
    output          inport_rvalid_o,
    output [DATA_WIDTH-1:0]   inport_rdata_o,
    output [1:0]    inport_rresp_o,

    // Default AXI outport
    // Write Address Channel (AW)
    input           outport_awready_i,
    output          outport_awvalid_o,
    output [ADDR_WIDTH-1:0]   outport_awaddr_o,
    // Write Data Channel (W)
    input           outport_wready_i,
    output          outport_wvalid_o,
    output [DATA_WIDTH-1:0]   outport_wdata_o,
    output [3:0]    outport_wstrb_o,
    // Write Response Channel (B)
    input           outport_bvalid_i,
    input  [1:0]    outport_bresp_i,
    output          outport_bready_o,
    // Read Address Channel (AR)
    input           outport_arready_i,
    output          outport_arvalid_o,
    output [ADDR_WIDTH-1:0]   outport_araddr_o,
    // Read Data Channel (R)
    input           outport_rvalid_i,
    input  [DATA_WIDTH-1:0]   outport_rdata_i,
    input  [1:0]    outport_rresp_i,
    output          outport_rready_o,

    // Peripheral 0 interface
    // Write Address Channel (AW)
    input           outport_peripheral0_awready_i,
    output          outport_peripheral0_awvalid_o,
    output [ADDR_WIDTH-1:0]   outport_peripheral0_awaddr_o,
    // Write Data Channel (W)
    input           outport_peripheral0_wready_i,
    output          outport_peripheral0_wvalid_o,
    output [DATA_WIDTH-1:0]   outport_peripheral0_wdata_o,
    output [3:0]    outport_peripheral0_wstrb_o,
    // Write Response Channel (B)
    input  [1:0]    outport_peripheral0_bresp_i,
    input           outport_peripheral0_bvalid_i,
    output          outport_peripheral0_bready_o,
    // Read Address Channel (AR)
    input           outport_peripheral0_arready_i,
    output          outport_peripheral0_arvalid_o,
    output [ADDR_WIDTH-1:0]   outport_peripheral0_araddr_o,
    // Read Data Channel (R)
    input  [1:0]    outport_peripheral0_rresp_i,
    input           outport_peripheral0_rvalid_i,
    input  [DATA_WIDTH-1:0]   outport_peripheral0_rdata_i,
    output          outport_peripheral0_rready_o
);

`define ADDR_SEL_W           1
`define PERIPH0_ADDR         32'h80000000
`define PERIPH0_MASK         32'h80000000

//-----------------------------------------------------------------
// AXI: Read
//-----------------------------------------------------------------
reg [3:0]              read_pending_q;
reg [3:0]              read_pending_r;
reg [`ADDR_SEL_W-1:0]  read_port_q;
reg [`ADDR_SEL_W-1:0]  read_port_r;

always @ *
begin
    read_port_r = `ADDR_SEL_W'b0;
    if ((inport_araddr_i & `PERIPH0_MASK) == `PERIPH0_ADDR) read_port_r = `ADDR_SEL_W'd1;
end

wire read_incr_w = (inport_arvalid_i && inport_arready_o);
