module axis_image_border_gen #(
    parameter IMG_WIDTH  = 336,
    parameter IMG_HEIGHT = 256,
    parameter BORDER_COLOR = 16'hFFFF,
    parameter DATA_MASK    = 16'h0000
)(
    input  wire            clk,
    input  wire            resetn,
    input  wire [15:0]     s_axis_tdata,
    input  wire            s_axis_tvalid,
    input  wire            s_axis_tlast,
    input  wire            s_axis_tuser,
    output wire [15:0]     m_axis_tdata,
    output wire            m_axis_tvalid,
    input  wire            m_axis_tready,
    output wire            m_axis_tlast,
    output wire            m_axis_tuser
);

    // State and Counter Registers
    reg [2:0] state, next_state;
    reg [15:0] x_count, y_count;
    reg border_valid;

    // FSM and Control Signals
    always @(posedge clk or negedge resetn) begin
        if (!resetn) begin
            state = ST_IDLE;
            next_state = ST_IDLE;
        else begin
            case (state)
                ST_IDLE: begin
                    if (s_axis_tuser) begin
                        state = ST_ROW_FIRST;
                        y_count = 0;
                    end
                end
                ST_ROW_FIRST: begin
                    if (x_count == IMG_WIDTH) begin
                        state = ST_PROCESS_ROW;
                        y_count = y_count + 1;
                    end
                    x_count = x_count + 1;
                end
                ST_PROCESS_ROW: begin
                    if (x_count == IMG_WIDTH) begin
                        state = ST_BORDER_ROW;
                        y_count = y_count + 1;
                    end
                    border_valid = (is_top_row || is_bottom_row || is_left_border || is_right_border);
                    if (border_valid) begin
                        m_axis_tdata = BORDER_COLOR;
                    else begin
                        m_axis_tdata = s_axis_tdata & DATA_MASK;
                    end
                    x_count = x_count + 1;
                end
                ST_BORDER_ROW: begin
                    if (y_count == IMG_HEIGHT) begin
                        state = ST_ROW_LAST;
                        y_count = y_count + 1;
                    end
                    border_valid = (is_top_row || is_bottom_row || is_left_border || is_right_border);
                    if (border_valid) begin
                        m_axis_tdata = BORDER_COLOR;
                    else begin
                        m_axis_tdata = s_axis_tdata & DATA_MASK;
                    end
                    x_count = x_count + 1;
                end
                ST_ROW_LAST: begin
                    if (s_axis_tlast) begin
                        state = ST_IDLE;
                        y_count = 0;
                    end
                    m_axis_tdata = s_axis_tdata & DATA_MASK;
                end
            end
            state = next_state;
        end
    end

    // State Definitions
    // ST_IDLE: Wait for frame start
    // ST_ROW_FIRST: Process first row with top border
    // ST_PROCESS_ROW: Process middle rows with left and right borders
    // ST_BORDER_ROW: Process bottom row with bottom border
    // ST_ROW_LAST: Complete processing and transition back to idle

    // Edge conditions
    wire is_top_row     = (y_count == 16'd0);
    wire is_bottom_row  = (y_count == IMG_HEIGHT + 1);
    wire is_left_border  = (x_count == 16'd0);
    wire is_right_border = (x_count == IMG_WIDTH + 1);
    wire is_border_pixel = (is_top_row || is_bottom_row || is_left_border || is_right_border);

    // Output data valid handling
    wire m_axis_tvalid;

    // Additional logic for AXI Stream protocol
    // (Assumes standard AXI Stream protocol constraints and proper tvalid/tready handling)

endmodule

output.rtl/axis_joiner.sv:
module axis_joiner(
    input clock,
    input rst,
    input [7:0] s_axis_tdata_1,
    input [1:0] s_axis_tvalid_1,
    input [1:0] s_axis_tready_1,
    input [0:0] s_axis_tlast_1,
    input [7:0] s_axis_tdata_2,
    input [1:0] s_axis_tvalid_2,
    input [1:0] s_axis_tready_2,
    input [0:0] s_axis_tlast_2,
    input [7:0] s_axis_tdata_3,
    input [1:0] s_axis_tvalid_3,
    input [1:0] s_axis_tready_3,
    input [0:0] s_axis_tlast_3,
    output [7:0] m_axis_tdata,
    output [1:0] m_axis_tvalid,
    output [1:0] m_axis_tready,
    output [0:0] m_axis_tlast,
    output [1:2] m_axis_tuser,
    output busy
);

    // FSM states
    state
        idle,
        state_1,
        state_2,
        state_3
    endstate;

    // State variables
    always @* begin
        case (s_axis_tvalid_1 | s_axis_tvalid_2 | s_axis_tvalid_3)
            // Priority: 1 > 2 > 3
            if (s_axis_tvalid_1) next_state = state_1;
            else if (s_axis_tvalid_2) next_state = state_2;
            else if (s_axis_tvalid_3) next_state = state_3;
            else next_state = idle;
        endcase
    endalways

    // Data buffers
    reg [7:0] data1, data2, data3;
    reg [1:0] valid1, valid2, valid3;
    reg [0:0] last1, last2, last3;

    // Current state
    state current_state = idle;

    // Output signals
    always @* begin
        case (current_state)
            idle:
                m_axis_tdata = 0;
                m_axis_tvalid = 0;
                m_axis_tready = 0;
                m_axis_tlast = 0;
                busy = 0;
                data1 = 0;
                data2 = 0;
                data3 = 0;
                valid1 = 0;
                valid2 = 0;
                valid3 = 0;
                last1 = 0;
                last2 = 0;
                last3 = 0;
                break;
            state_1:
                if (s_axis_tvalid_1) begin
                    m_axis_tdata = s_axis_tdata_1;
                    m_axis_tvalid = 1;
                    m_axis_tready = 1;
                    m_axis_tlast = 0;
                    m_axis_tuser = 0x1;
                    busy = 1;
                    // Wait for tlast
                    data1 = s_axis_tdata_1;
                    valid1 = 1;
                    last1 = 0;
                    next_state = idle;
                    break;
                end
            state_2:
                if (s_axis_tvalid_2) begin
                    m_axis_tdata = s_axis_tdata_2;
                    m_axis_tvalid = 1;
                    m_axis_tready = 1;
                    m_axis_tlast = 0;
                    m_axis_tuser = 0x2;
                    busy = 1;
                    data2 = s_axis_tdata_2;
                    valid2 = 1;
                    last2 = 0;
                    next_state = idle;
                    break;
                end
            state_3:
                if (s_axis_tvalid_3) begin
                    m_axis_tdata = s_axis_tdata_3;
                    m_axis_tvalid = 1;
                    m_axis_tready = 1;
                    m_axis_tlast = 0;
                    m_axis_tuser = 0x3;
                    busy = 1;
                    data3 = s_axis_tdata_3;
                    valid3 = 1;
                    last3 = 0;
                    next_state = idle;
                    break;
                end
        endcase
    endalways

    // Output m_axis_tdata
    wire m_axis_tdata = (current_state == idle) ? 0 : (current_state == state_1 ? data1 : (current_state == state_2 ? data2 : data3));

    // Output m_axis_tvalid
    wire m_axis_tvalid = (current_state == idle) ? 0 : 1;

    // Output m_axis_tready
    wire m_axis_tready = (current_state == idle) ? 0 : 1;

    // Output m_axis_tlast
    wire m_axis_tlast = (current_state == idle) ? 0 : 0;

    // Output m_axis_tuser
    wire m_axis_tuser = (current_state == idle) ? 0 : (current_state == state_1 ? 0x1 : (current_state == state_2 ? 0x2 : 0x3));

    // Output busy
    wire busy = (current_state != idle);

endmodule

output.rtl/barrel_shifter_8bit.sv:
module barrel_shifter_8bit (
    input data_in,
    input shift_bits,
    input left_right,
    output data_out
);

    reg [7:0] shifted_left[8], shifted_right[8];

    // Left shifts
    shifted_left[0] = data_in;
    shifted_left[1] = data_in << 1;
    shifted_left[2] = data_in << 2;
    shifted_left[3] = data_in << 3;
    shifted_left[4] = data_in << 4;
    shifted_left[5] = data_in << 5;
    shifted_left[6] = data_in << 6;
    shifted_left[7] = data_in << 7;

    // Right shifts
    shifted_right[0] = data_in;
    shifted_right[1] = data_in >> 1;
    shifted_right[2] = data_in >> 2;
    shifted_right[3] = data_in >> 3;
    shifted_right[4] = data_in >> 4;
    shifted_right[5] = data_in >> 5;
    shifted_right[6] = data_in >> 6;
    shifted_right[7] = data_in >> 7;

    // Select the output based on shift direction
    data_out = left_right ? shifted_left[shift_bits] : shifted_right[shift_bits];
endmodule

