output.rtl/barrel_shifter.sv:
module barrel_shifter #(
    parameter data_width = 16,
    parameter shift_bits_width = 4
)(
    input [data_width-1:0] data_in,
    input [shift_bits_width-1:0] shift_bits,
    input [2:0] mode,
    input enable,
    input enable_parity,
    output reg [data_width-1:0] data_out,
    output reg parity_out
);

    // New input ports
    input enable_parity;

    // Error output
    output reg error;

    // Case statement for modes
    case (mode)
        3'b000: begin
            if (left_right)
                data_out = data_in << shift_bits;
            else
                data_out = data_in >> shift_bits;
        end
        3'b001: begin
            if (left_right)
                data_out = data_in << shift_bits;
            else
                data_out = $signed(data_in) >>> shift_bits;
        end
        3'b010: begin
            if (left_right)
                data_out = (data_in << shift_bits) | (data_in >> (data_width - shift_bits));
            else
                data_out = (data_in >> shift_bits) | (data_in << (data_width - shift_bits));
        end
        3'b011: begin
            if (left_right)
                data_out = (data_in << shift_bits) & mask;
            else
                data_out = (data_in >> shift_bits) & mask;
        end
        3'b100: begin
            if (left_right) {
                data_out = data_in + shift_bits;
            } else {
                data_out = data_in - shift_bits;
            }
            if (data_out < 0) {
                data_out += (1 << data_width);
            }
        end
        3'b101: begin
            if (data_in == 0) {
                data_out = 0;
            } else {
                int pos = 0;
                for (int i = 0; i < data_width; i++) {
                    if ((data_in >> i) & 1) {
                        pos = i;
                    }
                }
                data_out = pos;
            }
        end
        3'b110: begin
            if (left_right) {
                data_out = (data_in + shift_bits) % data_width;
            } else {
                data_out = (data_in - shift_bits) % data_width;
            }
        end
        default: begin
            data_out = {data_width{1'b0}};
            parity_out = 0;
            error = 1;
        end
    endcase
    // Additional logic for parity calculation
    if (enable_parity) {
        parity_out = data_out;
        parity_out = parity_out[0];
    }
    // Error handling for invalid shift amounts
    if (shift_bits >= data_width || shift_bits < 0) {
        data_out = {data_width{1'b0}};
        error = 1;
    }
endmodule

