module barrel_shifter #(
    parameter data_width = 16,     
    parameter shift_bits_width = 4  
)(
    input [data_width-1:0] data_in,
    input [shift_bits_width-1:0] shift_bits,
    input [2:0] mode,
    input left_right,
    input [data_width-1:0] mask,
    input enable,
    input enable_parity,
    input condition,
    input [1:0] bit_op_type,
    input [data_width-1:0] mask,
    output reg [data_width-1:0] data_out,
    output reg parity_out,
    output reg error_out,
    output reg error_out2
);

always @(*) begin
    if (!enable) begin
        data_out = data_out;
        error_out = 0;
        parity_out = 0;
    end else begin
        error_out = 0;
        error_out2 = 0;
        case (mode)
            3'b000: begin  
                if (shift_bits >= data_width) begin
                    error_out = 2'b10;  
                    data_out = {data_width{1'b0}};
                end else if (left_right) begin
                    data_out = data_in << shift_bits;
                end else begin
                    data_out = data_in >> shift_bits;
                end
            end
            3'b001: begin  
                if (shift_bits >= data_width) begin
                    error_out = 2'b10;  
                    data_out = {data_width{1'b0}};
                end else if (left_right) begin
                    data_out = data_in << shift_bits;
                end else begin
                    data_out = $signed(data_in) >>> shift_bits;
                end
            end
            3'b010: begin 
                if (shift_bits >= data_width) begin
                    error_out = 2'b10;  
                    data_out = {data_width{1'b0}};
                end else if (left_right) begin
                    data_out = (data_in << shift_bits) | (data_in >> (data_width - shift_bits));
                end else begin
                    data_out = (data_in >> shift_bits) | (data_in << (data_width - shift_bits));
                end
            end
            3'b011: begin  
                if (shift_bits >= data_width) begin
                    error_out = 2'b10;  
                    data_out = {data_width{1'b0}};
                end else if (left_right) begin
                    data_out = data_in & mask;
                end else begin
                    data_out = data_in & mask;
                end
            end
            3'b100: begin 
                if (left_right) begin
                    data_out = data_in + shift_bits;  
                end else begin
                    data_out = data_in - shift_bits;  
                end
            end
            3'b101: begin  
                data_out = 0;
                for (int i = data_width-1; i >= 0; i = i - 1) begin
                    if (data_in[i] == 1 && data_out == 0) begin
                        data_out = i;  
                    end
                end
            end
            3'b110: begin 
                if (left_right) begin
                    data_out = (data_in + shift_bits) % data_width; 
                end else begin
                    data_out = (data_in - shift_bits) % data_width; 
                end
            end
            3'b111: begin  
                if (bit_op_type == 2'b00) begin
                    // Toggle bits
                    data_out = data_in ^ condition;
                elsif (bit_op_type == 2'b01) begin
                    // Set bits
                    data_out = data_in | condition;
                elsif (bit_op_type == 2'b10) begin
                    // Clear bits
                    data_out = data_in & ~condition;
