    input clock,
    input rst,
    output ms_hr, ls_hr,
    output ms_min, ls_min,
    output ms_sec, ls_sec
) {
    reg state = 0; // 0: seconds, 1: minutes, 2: hours

    reg[8] sec_counter, min_counter, hr_counter;

    always clock edge positive:
        case (state)
            0: 
                sec_counter = sec_counter + 1;
                if (sec_counter == 10) begin
