                if (hr_counter == 24) begin
                    hr_counter = 0;
                    state = 0;
                end
        endcase

        // Reset if rst is high
        if (rst) begin
            state = 0;
            sec_counter = 0;
            min_counter = 0;
            hr_counter = 0;
        end

