        ls_sec = sec_counter & 0x0F;
        ms_min = (min_counter >> 4) & 0x0F;
        ls_min = min_counter & 0x0F;
        ms_hr = (hr_counter >> 4) & 0x0F;
        ls_hr = hr_counter & 0x0F;
    endmodule

