// bcd | excess3 | error
// 0000 | 0011     0
// 0001 | 0010     0
// 0010 | 0001     0
// 0011 | 0000     0
// 0100 | 0101     0
// 0101 | 0100     0
// 0110 | 0100     0
// 0111 | 0011     0
// 1000 | 1101     0
// 1001 | 1100     0
// 1010 | 0000     1
// 1011 | 0000     1
// 1100 | 0000     1
// 1101 | 0000     1
// 1110 | 0000     1
// 1111 | 0000     1

// Implementation:
output [3:0] excess3;
output error;

