                                if (left_child[root] == 0) begin
                                    root <= {left_child[root], temp_data};
                                    left_child[root] <= temp_data;
                                    build_state <= INSERT;
                                end else begin
                                    current_node <= left_child[root];
                                    while (current_node != 0 && right_child[current_node] == 0) begin
