            case (state)
                IDLE: begin
                    grant1 <= 0;
                    grant2 <= 0;
                end
                GRANT_1: begin
                    grant1 <= 1;
                    grant2 <= 0;
                end
                GRANT_2: begin
                    grant1 <= 0;
                    grant2 <= 1;
                end
                CLEAR: begin
                    grant1 <= 0;
                    grant2 <= 0;
                end
            endcase
        end
    end

