module enhanced_fsm_signal_processor (
    input wire i_clk,
    input wire i_rst_n,
    input wire i_enable,
    input wire i_clear,
    input wire i_ack,
    input wire i_fault,
    input [5] i_vector_1,
    input [5] i_vector_2,
    input [5] i_vector_3,
    input [5] i_vector_4,
    input [5] i_vector_5,
    input [5] i_vector_6,
    output reg o_ready,
    output reg o_error,
    output reg [1] o_fsm_status,
    output [8] o_vector_1,
    output [8] o_vector_2,
    output [8] o_vector_3,
    output [8] o_vector_4
);

    // FSM states
    reg fsm_state = 0; // 0: IDLE, 1: PROCESS, 2: READY, 3: FAULT

    // State transition table
    always @* begin
        if (i_rst_n) begin
            fsm_state = 0;
            o_ready = 0;
            o_error = 0;
            o_fsm_status = 0b00;
        end else if (i_enable) begin
            fsm_state = 1;
        end else if (i_ack) begin
            fsm_state = 2;
        end else if (i_fault) begin
            fsm_state = 3;
        end
    end

    // Vector processing
    wire [31:0] process_bus = 0;
    always @* begin
        if (fsm_state == 1) begin
            process_bus = (i_vector_1 << 25) | (i_vector_2 << 20) | (i_vector_3 << 15) | (i_vector_4 << 10) | (i_vector_5 << 5) | i_vector_6;
            process_bus = process_bus + 2;
            o_vector_1 = (process_bus >> 24) & 0xFF;
            o_vector_2 = (process_bus >> 19) & 0xFF;
            o_vector_3 = (process_bus >> 14) & 0xFF;
            o_vector_4 = (process_bus >> 9) & 0xFF;
        end else if (fsm_state == 3 && i_clear && !i_fault) begin
            o_vector_1 = 0;
            o_vector_2 = 0;
            o_vector_3 = 0;
            o_vector_4 = 0;
            fsm_state = 0;
        end
    end

    // State outputs
    always @* begin
        o_fsm_status = fsm_state;
    end

    // Error output
    always @* begin
        o_error = i_fault;
    end
endmodule

output.rtl/low_pass_filter.sv:
module low_pass_filter(
    input clock,
    input reset,
    input data_in,
    input valid_in,
    input coeffs,
    output data_out,
    output valid_out
);

    // Internal signals
    reg data_reg[NUM_TAPS][DATA_WIDTH];
    reg coeff_reg[NUM_TAPS][COEFF_WIDTH];
    reg temp_mult[NUM_TAPS];
    reg sum_result;
    reg valid_reg;

    // unpack data_in
    integer i, j;
    initial begin
        // Initialize all registers to 0
        data_reg[0][0] = 0;
        coeff_reg[0][0] = 0;
    end

    always @(posedge clock or posedge reset) begin
        if (reset) begin
            // Clear all registers
            data_reg[0][0] = 0;
            coeff_reg[0][0] = 0;
            temp_mult[0] = 0;
            sum_result = 0;
            valid_reg = 0;
        end else begin
            // Store data_in and coeffs
            data_reg[0][0] = data_in;
            coeff_reg[0][0] = coeffs[0];
            valid_reg = valid_in;

            // Unpack data and coeffs
            for (i = 0; i < NUM_TAPS; i++) begin
                for (j = 0; j < DATA_WIDTH; j++) begin
                    data_reg[i][j] = (data_in >> (NUM_TAPS * DATA_WIDTH - 1 - i * DATA_WIDTH - j)) & ((1 << DATA_WIDTH) - 1);
                end
            end

            for (i = 0; i < NUM_TAPS; i++) begin
                for (j = 0; j < COEFF_WIDTH; j++) begin
                    coeff_reg[i][j] = (coeffs[i] >> (COEFF_WIDTH - 1 - j)) & ((1 << COEFF_WIDTH) - 1);
                end
            end

            // Element-wise multiplication
            for (i = 0; i < NUM_TAPS; i++) begin
                temp_mult[i] = data_reg[i][0] * coeff_reg[i][0];
            end

            // Summation
            sum_result = 0;
            for (i = 0; i < NUM_TAPS; i++) begin
                sum_result = sum_result + temp_mult[i];
            end

            // Pack result
            data_out = sum_result;
        end
    end

    // Output validity
    valid_out = valid_reg;

endmodule

output.rtl/decimator_and_peak_detector.sv:
module advanced_decimator_with_adaptive_peak_detection(
    input clock,
    input reset,
    input valid_in,
    output data_out,
    output peak_value
);

    reg data_reg[N];
    reg [DATA_WIDTH-1:0] samples_FIFO_in[N/DEC_FACTOR];
    reg [DATA_WIDTH-1:0] samples_FIFO_out[N/DEC_FACTOR];
    reg [DATA_WIDTH-1:0] decimated_FIFO_in[N/DEC_FACTOR];
    reg [DATA_WIDTH-1:0] decimated_FIFO_out[N/DEC_FACTOR];
    reg [DATA_WIDTH-1:0] peak_value_reg;

    initial begin
        data_reg = 0;
    end

    always @(posedge clock or valid_in) begin
        if (reset) begin
            data_reg = 0;
            samples_FIFO_in = 0;
            decimated_FIFO_in = 0;
        end
        else
            data_reg = data_in;
        end
    end

    // Unpack data
    always begin
        for (int i = 0; i < N; i++) begin
            samples_FIFO_in[i] = (data_reg[i] << (DATA_WIDTH * (N - 1 - i))) & ((1 << (DATA_WIDTH * N)) - 1);
        end
    end

    // Decimate
    always begin
        for (int i = 0; i < samples_FIFO_in.size; i++) begin
            if (i % DEC_FACTOR == 0) begin
                decimated_FIFO_out[0] = samples_FIFO_in[0];
                decimated_FIFO_out[0] <= samples_FIFO_in[0];
                decimated_FIFO_in[0] = samples_FIFO_in[1];
                decimated_FIFO_in[1] = samples_FIFO_in[2];
                decimated_FIFO_in[2] = samples_FIFO_in[3];
                decimated_FIFO_in[3] = samples_FIFO_in[4];
            end
        end
    end

    // Peak detection
    always begin
        peak_value_reg = decimated_FIFO_in[0];
        for (int i = 1; i < decimated_FIFO_in.size; i++) begin
            if (decimated_FIFO_in[i] > peak_value_reg) begin
                peak_value_reg = decimated_FIFO_in[i];
            end
        end
    end

    // Pack decimated data
    always begin
        data_out = 0;
        for (int i = 0; i < decimated_FIFO_out.size; i++) begin
            data_out |= (decimated_FIFO_out[i] << (DATA_WIDTH * (decimated_FIFO_out.size - 1 - i)));
        end
    end

    // Output valid
    always begin
        valid_out = valid_in;
    end
endmodule

output.rtl/sgd_linear_regression.sv:
module sgd_linear_regression #(
    parameter DATA_WIDTH = 16, 
    parameter LEARNING_RATE = 3'd1
) (
    input  logic clk,                               // Clock
    input  logic reset,                             // Asynchronous reset
    input  logic signed [DATA_WIDTH-1:0] x_in,      // Input data (x)
    input  logic signed [DATA_WIDTH-1:0] y_true,    // True output (target)
    output logic signed [DATA_WIDTH-1:0] w,     // Trained weight
    output logic signed [DATA_WIDTH-1:0] b      // Trained bias
);
    localparam NBW_PRED  = 2*DATA_WIDTH + 1;
    localparam NBW_ERROR = NBW_PRED + 1;
    localparam NBW_DELTA = 3 + NBW_ERROR + DATA_WIDTH;

    // Intermediate values
    logic signed [NBW_PRED-1:0] y_pred;  
    logic signed [NBW_ERROR-1:0] error;  
    logic signed [NBW_DELTA-1:0] delta_w; 
    logic signed [NBW_DELTA-1:0] delta_b;

    // Predicted output calculation
    always_comb begin
        y_pred = (w * x_in) + b;
    end

    // Error calculation
    error = y_true - y_pred;

    // Weight and bias updates
    delta_w = LEARNING_RATE * error * x_in;
    delta_b = LEARNING_RATE * error;

    // Weight and bias adjustment with reset control
    always begin
        if (reset) begin
            w = 0;
            b = 0;
        else begin
            // Apply the deltas with bit masking to maintain width
            w = (w + delta_w) & ((1 << DATA_WIDTH) - 1);
            b = (b + delta_b) & ((1 << DATA_WIDTH) - 1);
        end
    end
endmodule

output.rtl/fsm_linear_reg.sv:
module fsm_linear_reg(
    input clock,
    input reset,
    input start,
    input x_in,
    input w_in,
    input b_in,
    output result1,
    output result2,
    output done
);

    parameter DATA_WIDTH = 16;

    reg result1, result2;
    reg [DATA_WIDTH+1] done;

    state
        IDLE,
        COMPUTE,
        DONE
    endstate

    always_comb state = IDLE | COMPUTE | DONE
    case (state)
        IDLE:
            if (start) begin
                state = COMPUTE;
                result1 = 0;
                result2 = 0;
                done = 0;
            end
        COMPUTE:
            result1 = (w_in * x_in) >> 1;
            result2 = b_in + (x_in >> 2);
            state = DONE;
        DONE:
            result1 = 0;
            result2 = 0;
            done = 1;
            state = IDLE;
    endcase

    // Reset handling
    if (reset) begin
        result1 = 0;
        result2 = 0;
        done = 0;
        state = IDLE;
    end

    // Latency handling
    // After start is asserted, results are ready after 2 clock cycles
    // Done signal is asserted after 3 clock cycles
endmodule

input.rtl/cont_adder_top.sv:
module continuous_adder (
    input logic         clk,         // Clock signal
    input logic         reset,       // Reset signal, Active high and Synchronous
    input logic [7:0]   data_in,     // Input data stream (8-bit)
    input logic         data_valid,  // Input data valid signal
    output logic [7:0]  sum_out,     // Output the accumulated sum
    output logic        sum_ready    // Signal to indicate sum is output and accumulator is reset
);

    logic [7:0] sum_accum;          // Internal accumulator to store the running sum

    // Sequential logic for sum accumulation
    always_ff @(posedge clk) begin
        if (reset) begin
            // On reset, clear the accumulator, reset sum_out and sum_ready
            sum_accum         <= 8'd0;
            sum_ready         <= 1'b0;
        end
        else begin
            if (data_valid) begin
                // Add input data to the accumulator
                sum_accum     <= sum_accum + data_in;

                // Check if the accumulated sum is >= 100
                if (sum_accum + data_in >= 8'd100) begin
                    // Output the current sum and reset the accumulator
                    sum_out   <= sum_accum + data_in; // Output the accumulated sum
                    sum_ready <= 1'b1;                // Indicate that the sum is ready
                    sum_accum <= 8'd0;                // Reset the accumulator
                end
                else begin
                    // Continue accumulating, but no output until the sum reaches 100
                    sum_ready <= 1'b0;                // No output yet
                end
            end
        end
    end

endmodule

