                ((sat_sum >= THRESHOLD_VALUE_3) || (sat_sum <= -THRESHOLD_VALUE_3)))
              state <= DONE;
          end
        end
        DONE: begin
          state <= IDLE;
          sum_accum <= 0;
          sample_count <= 0;
        end
        default: state <= IDLE;
      endcase
    end
  end

  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      sum_out <= 0;
      avg_out <= 0;
      sum_ready <= 0;
      threshold_1 <= 0;
      threshold_2 <= 0;
      threshold_3 <= 0;
      busy <= 0;
    end else begin
      busy <= (state == ACCUM);
      if (state == DONE) begin
        sum_out <= sum_accum;
        avg_out <= (ACCUM_MODE == 1) ? (sum_accum / sample_count) : 0;
        sum_ready <= 1;
        if ((sum_accum >= THRESHOLD_VALUE_1) || (sum_accum <= -THRESHOLD_VALUE_1))
          threshold_1 <= 1;
        else
          threshold_1 <= 0;
        if ((sum_accum >= THRESHOLD_VALUE_2) || (sum_accum <= -THRESHOLD_VALUE_2))
          threshold_2 <= 1;
        else
          threshold_2 <= 0;
        if ((sum_accum >= THRESHOLD_VALUE_3) || (sum_accum <= -THRESHOLD_VALUE_3))
          threshold_3 <= 1;
        else
          threshold_3 <= 0;
      end else begin
        sum_out <= 0;
        avg_out <= 0;
        sum_ready <= 0;
        threshold_1 <= 0;
        threshold_2 <= 0;
        threshold_3 <= 0;
      end
    end
  end

endmodule

