                    if (overflow32 #16(accumulator)) begin
                        dot_product_valid_out = 0;
                    end else begin
                        dot_product_valid_out = 0;
                    end
                end else begin
                    // Invalid input, wait for valid signals
                    state = COMPUTE;
                end
            end
            state = OUTPUT;
            dot_product_valid_out = 1;
        end
    end
