        .clk   (clk),
        .reset (~rst_n),
        .d     (st7),
        .q     (st8)
    );


    //////////////////////////////////////////////
    // Stage 7: F6 = 2 - D12, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F6 = TWO - D12;
    end

    assign D13 = F6 * D12;
    assign N13 = F6 * N12;

    reg18 reg_divisor_stage8(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D13[26:9]),
        .data_out(D14)
    );
    reg18 reg_dividend_stage8(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N13[26:9]),
        .data_out(N14)
    );

    dff1 ff10(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st8),
        .q     (st9)
    );


    //////////////////////////////////////////////
    // Stage 8: F7 = 2 - D14, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F7 = TWO - D14;
    end

    assign D15 = F7 * D14;
    assign N15 = F7 * N14;

    reg18 reg_divisor_stage9(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D15[26:9]),
        .data_out(D16)
    );
    reg18 reg_dividend_stage9(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N15[26:9]),
        .data_out(N16)
    );

    dff1 ff11(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st9),
        .q     (st10)
    );

    //////////////////////////////////////////////
    // Stage 9: F8 = 2 - D16, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F8 = TWO - D16;
    end

    assign D17 = F8 * D16;
    assign N17 = F8 * N16;

    reg18 reg_divisor_stage10(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D17[26:9]),
        .data_out(D18)
    );
    reg18 reg_dividend_stage10(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N17[26:9]),
        .data_out(N18)
    );

    dff1 ff12(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st10),
        .q     (st11)
    );

    //////////////////////////////////////////////
    // Stage 10: F9 = 2 - D18, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F9 = TWO - D18;
    end

    assign D19 = F9 * D18;
    assign N19 = F9 * N18;

    reg18 reg_divisor_stage11(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D19[26:9]),
        .data_out(D20)
    );
    reg18 reg_dividend_stage11(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N19[26:9]),
        .data_out(N20)
    );

    dff1 ff13(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st11),
        .q     (st12)
    );

    always_comb begin
        N21 = N20;
    end

    // Final output register
    reg18 reg_quotient_out(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N21),
        .data_out(dv_out)
    );

    // Final pipeline control
    dff1 ff14(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st12),
        .q     (valid)
    );

endmodule

////////////////////////////////////////////////
// Pre-scaling (Prescaling) Module
////////////////////////////////////////////////
module pre_scaler (
    input  logic [17:0] a,  // unsigned divisor
    input  logic [17:0] c,  // unsigned dividend
    output logic [17:0] b,  // prescaled divisor
    output logic [17:0] d   // prescaled dividend
);
    // For simplicity, if 'a' is large, we shift until it is < 1.0 in Q9.9 format
    // That means the integer bits of 'a' must be 0. We find how many leading bits
    // we need to shift out.

    always_comb begin : SHIFT_LOGIC
        // 'a' has 18 bits in total, where the top 9 bits are integer, bottom 9 bits are fractional.
        // We want the integer part of 'a' to be 0 => 'a[17:9]' should be zero after shifting.

        if (a[17]) begin
            b = a >> 8;
            d = c >> 8;
        end
        else if (a[16]) begin
            b = a >> 7;
            d = c >> 7;
        end
        else if (a[15]) begin
            b = a >> 6;
            d = c >> 6;
        end
        else if (a[14]) begin
            b = a >> 5;
            d = c >> 5;
        end
        else if (a[13]) begin
            b = a >> 4;
            d = c >> 4;
        end
        else if (a[12]) begin
            b = a >> 3;
            d = c >> 3;
        end
        else if (a[11]) begin
            b = a >> 2;
            d = c >> 2;
        end
        else if (a[10]) begin
            b = a >> 1;
            d = c >> 1;
        end
        else begin
            b = a;
            d = c;
        end
    end
endmodule

////////////////////////////////////////////////
// Single-bit DFF
////////////////////////////////////////////////
module dff1 (
    input  logic clk,
    input  logic reset,
    input  logic d,
    output logic q
);
    always_ff @(posedge clk) begin
        if (reset) 
            q <= 1'b0;
        else
            q <= d;
    end
endmodule


////////////////////////////////////////////////
// 18-bit register (parallel load)
////////////////////////////////////////////////
module reg18 (
    input  logic        clk,
    input  logic        reset,
    input  logic [17:0] data_in,
    output logic [17:0] data_out
);
    always_ff @(posedge clk) begin
        if (reset) 
            data_out <= 18'd0;
        else
            data_out <= data_in;
    end
endmodule

