               OUT  <= A_ff;
            end
            S2: begin
               if (greater_than)
                  A_ff <= A_ff - B_ff;
            end
            S3: begin
               if (!equal & !greater_than)
                  B_ff <= B_ff - A_ff;
            end
            default: begin
               A_ff <= 'b0;
               B_ff <= 'b0;
