               greater_than = 1'b0;
            end
         endcase
      end
   end

   // State transition logic: Determine next state based on current state and inputs
   always_comb begin
      case(controlpath_state)
         S0: begin
             if(!go)
                controlpath_state <= S0;
             else if (equal)
                controlpath_state <= S1;
             else if (greater_than)
                controlpath_state <= S2;
             else
                controlpath_state <= S3;
         end
         S1: begin
             controlpath_state <= S0;
         end
         S2: begin
             if(equal)
                controlpath_state <= S1;
