input.rtl/hamming_rx.sv:
module hamming_code_receiver (
  input[7:0] data_in,
  output [3:0] data_out
);

  wire c1,c2,c3,error;
  reg[7:0] correct_data;


  assign c3 =  data_in[1] ^ data_in[3] ^ data_in[5] ^ data_in[7];
  assign c2 =  data_in[2] ^ data_in[3] ^ data_in[6] ^ data_in[7];
  assign c1 =  data_in[4] ^ data_in[5] ^ data_in[6] ^ data_in[7];

  assign error = ({c3,c2,c1}==3'b000) ? 1'b0 : 1'b1;

  always@(*)
  begin
    correct_data = 0;
    if(error)
    begin
      correct_data             = data_in;
      correct_data[{c1,c2,c3}] = ~correct_data[{c1,c2,c3}];
    end
    else
    begin
      correct_data             = data_in;
    end
  end

 assign data_out = {correct_data[7],correct_data[6],correct_data[5],correct_data[3]};

endmodule

output.rtl/hamming_tx.sv:
module hamming_tx #(
    // Parameters
    parameter DATA_WIDTH       = 4,
    parameter PART_WIDTH      = 4,
    parameter PARITY_BIT      = 3,
    parameter NUM_MODULES      = DATA_WIDTH / PART_WIDTH
)
(
    input  [DATA_WIDTH-1:0]    data_in,
    output [NUM_MODULES * (PARITY_BIT + DATA_WIDTH + 1)-1:0] data_out
);

    genvar i;

    // Calculate encoded data width
    parameter ENCODED_DATA     = PARITY_BIT + DATA_WIDTH + 1;
    parameter ENCODED_DATA_BIT = $clog2(ENCODED_DATA);

    // Initialize output
    reg [NUM_MODULES * ENCODED_DATA - 1:0] data_out = 0;

    // Process each module
    for (i = 0; i < NUM_MODULES; i = i + 1) begin
        // Extract slice for current module
        reg [PART_WIDTH-1:0] slice = data_in[(i * PART_WIDTH):((i * PART_WIDTH) + PART_WIDTH - 1)];

        // Process slice through Hamming transmitter
        reg [ENCODED_DATA-1:0] encoded_slice;
        reg [PARITY_BIT-1:0] parity;
        integer j, count;
        reg [ENCODED_DATA_BIT:0] pos;

        always @(*) begin
            encoded_slice = 0;
            parity = 0;
            count = 0;

            for (pos = 1; pos < ENCODED_DATA; pos = pos + 1) begin
                if ((pos & (pos - 1)) != 0) begin
                    encoded_slice[pos] = slice[count];
                    count = count + 1;
                end
            end

            for (j = 0; j < PARITY_BIT; j = j + 1) begin
                for (i = 1; i <= ENCODED_DATA-1; i = i + 1) begin
                    if ((i & (1 << j)) != 0) begin
                        parity[j] = parity[j] ^ encoded_slice[i];
                    end
                end
            end

            for (j = 0; j < PARITY_BIT; j = j + 1) begin
                encoded_slice[(1 << j)] = parity[j];
            end
        end

        // Update final output
        data_out = (data_out << ENCODED_DATA) | encoded_slice;
    end
endmodule



module t_hamming_tx #(
    parameter DATA_WIDTH       = 4,
    parameter PARITY_BIT       = 3,
    parameter ENCODED_DATA     = PARITY_BIT + DATA_WIDTH + 1,
    parameter ENCODED_DATA_BIT = $clog2(ENCODED_DATA)
)(
    input  [DATA_WIDTH-1:0]       data_in,
    output  reg[ENCODED_DATA-1:0] data_out
);

    reg [PARITY_BIT-1:0] parity;
    integer i, j, count;
    reg [ENCODED_DATA_BIT:0] pos;

    always @(*) begin
        data_out = 0;
        parity   = 0;
        count    = 0;

        for (pos = 1; pos < ENCODED_DATA; pos = pos + 1) begin
            if ((pos & (pos - 1)) != 0) begin
                data_out[pos] = data_in[count];
                count = count + 1;
            end
        end

        for (j = 0; j < PARITY_BIT; j = j + 1) begin
            for (i = 1; i <= ENCODED_DATA-1; i = i + 1) begin
                if ((i & (1 << j)) != 0) begin
                    parity[j] = parity[j] ^ data_out[i];
                end
            end
        end

        for (j = 0; j < PARITY_BIT; j = j + 1) begin
            data_out[(1 << j)] = parity[j];
        end
    end
endmodule

input.rtl/hebb_gates.sv:
module hebb_gates(
   input  logic               clk,
   input  logic               rst,
   input  logic               start, // To start the FSM
   input  logic  signed [3:0] a, // First Input
   input  logic  signed [3:0] b, // Second Input
   input  logic         [1:0] gate_select, // To provide the targets for a selected gate in order to train
   output logic  signed [3:0] w1, // Weight 1 obtained by training
   output logic  signed [3:0] w2, // Weight 2 obtained by training
   output logic  signed [3:0] bias,// Bias obtained by training
   output logic [3:0] present_state,// Present State of the Training FSM
   output logic [3:0] next_state // Next_State of the Training FSM

);
   logic signed [3:0] t1;
   logic signed [3:0] t2;
   logic signed [3:0] t3;
   logic signed [3:0] t4;

   gate_target dut(
       .gate_select(gate_select),
       .o_1        (t1),
       .o_2        (t2),
       .o_3        (t3),
       .o_4        (t4)
   );

   localparam [3:0] S0 = 4'd0;
   localparam [3:0] S1 = 4'd1;
   localparam [3:0] S2 = 4'd2;
   localparam [3:0] S3 = 4'd3;
   localparam [3:0] S4 = 4'd4;
   localparam [3:0] S5 = 4'd5;
   localparam [3:0] S6 = 4'd6;
   localparam [3:0] S7 = 4'd7;
   localparam [3:0] S8 = 4'd8;
   localparam [3:0] S9 = 4'd9;
   localparam [3:0] S10 = 4'd10;

   logic [2:0] iteration;
   logic signed [3:0] x1;
   logic signed [3:0] x2;
   logic signed [3:0] delta_w1;
   logic signed [3:0] delta_w2;
   logic signed [3:0] delta_b;
   logic signed [3:0] w1_reg;
   logic signed [3:0] w2_reg;
   logic signed [3:0] bias_reg;
   logic signed [1:0] target;
   logic delta_en;
   logic sum_en;
   logic clr_en;
   logic cap_en;

   always_comb begin
     if(cap_en ) begin
        x1 = a;
        x2 = b;
     end else begin
        x1 = x1 + 4'h0;
        x2 = x2 + 4'h0;
     end

   end

   always_comb begin

     if(delta_en) begin
       delta_w1 = x1 * target;
       delta_w2 = x2 * target;
       delta_b  = target;
     end else begin
       delta_w1 = delta_w1 + 4'h0;
       delta_w2 = delta_w2 + 4'h0;
       delta_b  = delta_b + 4'h0; 
   end

  end

  always_comb begin

     if(sum_en) begin
       w1_reg = w1_reg + delta_w1;
       w2_reg = w2_reg + delta_w2;
       bias_reg = bias_reg + delta_b;
     end else begin
       w1_reg = w1_reg + 4'h0;
       w2_reg = w2_reg + 4'h0;
       bias_reg = bias_reg + 4'h0;
   end
  end

   always_comb begin

     if(clr_en) begin
       w1_reg = 0;
       w2_reg = 0;
       bias_reg = 0;
     end else begin
       w1_reg = w1_reg + 4'h0;
       w2_reg = w2_reg + 4'h0;
       bias_reg = bias_reg + 4'h0; 
    end
   end

   always_ff@(posedge clk or negedge rst) begin
       if(!rst) begin
          present_state <= S0;
          iteration <= 0;
        end else
          present_state <= next_state;
   end

   always_comb begin
        next_state = present_state;

     case(present_state)
             S0  : begin 
                      if(start)
                         next_state = S1;
                      else
                         next_state = S0;
                   end
             S1  : begin 
                         next_state = S2;
                   end
             S2  : begin 
                      if(iteration == 0)
                        next_state = S3;
                     else if(iteration == 1)
                        next_state = S4;
                     else if(iteration == 2)
                        next_state = S5;
                     else 
                        next_state = S6;
                   end
             S3  : begin 
                         next_state = S7;

                   end
             S4  : begin 
                         next_state = S7;
                  end
             S5  : begin 
                         next_state = S7;
                  end
             S6  : begin 
                         next_state = S7;
                  end
             S7  :begin
                         next_state = S8;
                  end
             S8  : begin
                         next_state = S9;
                  end
             S9  : begin
                      if(iteration < 4)
                         next_state = S1;
                      else
                         next_state = S10;
                   end
             S10 : begin
                      next_state = S0;
                   end
             default : ;
     endcase
   end 

   always_comb begin

      case(present_state)
             S0 : begin
                    clr_en = 1;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en   = 0;
                    iteration = 0;
                    target = target + 4'h0;
                  end 
             S1 : begin
                    clr_en = 0;
                    cap_en = 1;
                    delta_en = 0;
                    sum_en = 0;  
                    iteration = iteration + 0;  
                    target = target + 4'h0;              
                  end
             S2 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0; 
                    iteration = iteration + 0;     
                    target = target + 4'h0;              
                  end
             S3 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = t1;
                  end
             S4 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = t2;
                  end     

             S5 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = t3;
                  end  
             S6 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = t4;
                  end        
             S7 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 1;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = target + 4'h0;
                  end
             S8 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 1;
                    iteration = iteration + 1;
                    target = target + 4'h0;
                  end
             S9 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = target + 4'h0;
                  end  
             S10 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = target + 4'h0;
                  end



           default : begin
                      clr_en = 0;
                      cap_en = 0;
                      delta_en = 0;
                      sum_en = 0;
                      iteration = 0;
                      target = target + 4'h0;
                     end
       endcase
   end
   assign w1 = w1_reg;
   assign w2 = w2_reg;
   assign bias = bias_reg;

endmodule

module gate_target(
   input  logic        [1:0] gate_select,
   output logic signed [3:0] o_1,
   output logic signed [3:0] o_2,
   output logic signed [3:0] o_3,
   output logic signed [3:0] o_4
);
   always_comb begin
     case(gate_select)
          2'b00 : begin 
                    o_1 =  1; 
                    o_2 = -1; 
                    o_3 = -1; 
                    o_4 = -1; 
                  end
          2'b01 : begin 
                    o_1 =  1; 
                    o_2 =  1; 
                    o_3 =  1; 
                    o_4 = -1; 
                  end
          2'b10 : begin 
                    o_1 =  1; 
                    o_2 =  1; 
                    o_3 =  1; 
                    o_4 = -1; 
                  end
          2'b11 : begin 
                    o_1 =  1; 
                    o_2 = -1; 
                    o_3 = -1; 
                    o_4 = -1; 
                  end
        default : begin
                    o_1 =  0; 
                    o_2 =  0; 
                    o_3 =  0; 
                    o_4 =  0; 
                  end
        endcase
   end
endmodule

