output.rtl/cvdp_copilot_perf_counters.sv:
module cvdp_copilot_perf_counters(
    input clock,
    input reset,
    input sw_req_i,
    input cpu_trig_i,
    output [CNT_W-1:0] p_count_o
);

    // Counter value
    reg [CNT_W-1:0] count_q;

    // Output signal
    reg [CNT_W-1:0] p_count_o_reg;

    always clocked+edge #+1 (
        if (reset) (
            count_q = 0;
        ) else if (cpu_trig_i) (
            count_q = count_q + 1;
        )
    );

    // Software request handling
    always clocked #+1 (
        if (sw_req_i) (
            p_count_o = p_count_o_reg;
            p_count_o_reg = 0;
        )
    );

    // Wrap around on overflow
    always @* begin
        p_count_o_reg = count_q;
    end

    // Counter initialization
    initial begin
        count_q = 0;
    end

endmodule

output.rtl/perfect_squares_generator.sv:
import struct

class SystemVerilog:
    def __init__(self):
        self._clk = 0
        self._reset = 0
        self._squares = [31'h800000]  # Initialize with the first square number (1)

    def update(self):
        if self._reset:
            self._squares = [31'h800000]  # Reset to 1
            self._clk = 1
            return
        n = self._clk
        next_n = (n ** 2)  # Calculate the next square number
        if next_n > 31'h3141593247:  # Check overflow
            self._squares = [31'h3141593247]  # Saturate at 32-bit max
        else:
            self._squares.append(next_n)
        self._clk += 1  # Increment the clock edge

    def get(self):
        return self._squares

