module pkt_detector #(
    parameter PKT_CNT_WIDTH = 4
) (
    input  logic                       reset,
    input  logic                       clk,
    input  logic [7:0]                 data_in,
    input  logic                       data_k_flag,
    output logic [PKT_CNT_WIDTH - 1:0] pkt_count,
    output logic [159:0]               pkt_data,
    output logic                       mem_read_detected,
    output logic                       mem_write_detected,
    output logic                       io_read_detected,
    output logic                       io_write_detected,
    output logic                       cfg_read0_detected,
    output logic                       cfg_write0_detected,
    output logic                       cfg_read1_detected,
    output logic                       cfg_write1_detected,
    output logic                       completion_detected,
    output logic                       completion_data_detected,
    output logic                       error_detected
);

localparam [7:0] START_SYMBOL = 8'hFB;
localparam [7:0] END_SYMBOL   = 8'hFD;
localparam       PKT_BYTES    = 20;

typedef enum logic [1:0] {
    S_IDLE     = 2'b00,
    S_ACTIVE   = 2'b01,
    S_WAIT_END = 2'b10,
    S_ERROR    = 2'b11
} state_t;

state_t curr_state, nxt_state;

logic [7:0]    byte_cnt;
logic [159:0]  pkt_reg;

// State Register
always_ff @(posedge clk or negedge reset) begin
    if (!reset)
        curr_state <= S_IDLE;
    else
        curr_state <= nxt_state;
end

// Next State Logic and Output Update
always_comb begin
    case (curr_state)
        S_IDLE: 
            if ((data_in == START_SYMBOL) && (data_k_flag == 1'b1))
                nxt_state = S_ACTIVE;
                mem_read_detected = 1;
                mem_write_detected = 1;
                io_read_detected = 1;
                io_write_detected = 1;
                cfg_read0_detected = 1;
                cfg_write0_detected = 1;
                completion_detected = 1;
                completion_data_detected = 1;
            else
                nxt_state = S_IDLE;
                mem_read_detected = 0;
                mem_write_detected = 0;
                io_read_detected = 0;
                io_write_detected = 0;
                cfg_read0_detected = 0;
                cfg_write0_detected = 0;
                completion_detected = 0;
                completion_data_detected = 0;

        S_ACTIVE: 
            byte_cnt <= byte_cnt + 1;
            pkt_reg <= (data_in << (byte_cnt * 8)) | pkt_reg;
            nxt_state = S_ACTIVE;

        S_WAIT_END: 
            if (pkt_reg[159:152] == END_SYMBOL)
                nxt_state = S_IDLE;
                mem_read_detected = 0;
                mem_write_detected = 0;
                io_read_detected = 0;
                io_write_detected = 0;
                cfg_read0_detected = 0;
                cfg_write0_detected = 0;
                completion_detected = 0;
                completion_data_detected = 0;
                pkt_data <= pkt_reg;
                pkt_count <= pkt_count + 1;
            else
                nxt_state = S_ERROR;
                error_detected = 1;

        S_ERROR: 
            if ((data_in == START_SYMBOL) && (data_k_flag == 1'b1))
                nxt_state = S_ACTIVE;
                mem_read_detected = 0;
                mem_write_detected = 0;
                io_read_detected = 0;
                io_write_detected = 0;
                cfg_read0_detected = 0;
                cfg_write0_detected = 0;
                completion_detected = 0;
                completion_data_detected = 0;
            else
                nxt_state = S_ERROR;
                mem_read_detected = 0;
                mem_write_detected = 0;
                io_read_detected = 0;
                io_write_detected = 0;
                cfg_read0_detected = 0;
                cfg_write0_detected = 0;
                completion_detected = 0;
                completion_data_detected = 0;

        default: nxt_state = S_IDLE;
    endcase
end

endmodule

