output.rtl/rounding.sv:
module rounding #(
  parameter WIDTH = 24
)(
  input logic  [WIDTH-1:0] in_data      , // Input value for rounding
  input logic              sign    , // Indicates sign of input (1: negative, 0: positive)
  input logic              roundin , // Round bit
  input logic              stickyin, // Sticky bit for precision
  input logic  [2:0]       rm      , // Rounding mode
  output logic [WIDTH-1:0] out_data     , // Rounded output
  output logic             inexact , // Indicates precision loss
  output logic             cout    , // Carry-out_data signal
  output logic             r_up      // Indicates rounding up
);

  localparam RNE = 3'b000; 
  localparam RTZ = 3'b001; 
  localparam RUP = 3'b010; 
  localparam RDN = 3'b011; 
  localparam RMM = 3'b100; 

  logic rounding_up;

  logic [WIDTH-1:0] truncated, [WIDTH-1:0] rounded;

  if (roundin) begin
    if (rm == RNE) begin
      // Round to nearest even
      truncated = in_data;
      if (sign) truncated = ~truncated & -1;
      if (truncated[WIDTH-1] & truncated[WIDTH-2]) begin
        if (truncated[WIDTH-2] == 0) begin
          // Tie case: round to nearest even
          if (truncated[WIDTH-3] & truncated[WIDTH-4]) begin
            truncated = truncated + 1;
          end
        end
      end
      rounded = truncated;
      rounding_up = truncated[WIDTH-2];
    elsif (rm == RTZ) begin
      // Round toward zero
      rounded = in_data;
      if (sign) rounded = ~rounded & -1;
    elsif (rm == RUP) begin
      // Round toward positive infinity
      if (sign) begin
        if (in_data) begin
          rounded = in_data + 1;
        end
      end else begin
        rounded = in_data;
      end
      rounding_up = 1;
    elsif (rm == RDN) begin
      // Round toward negative infinity
      if (!sign) begin
        if (in_data) begin
          rounded = in_data;
        end else begin
          rounded = in_data - 1;
        end
      end else begin
        rounded = in_data;
      end
      rounding_up = 1;
    elsif (rm == RMM) begin
      // Round to maximum magnitude
      if (sign) begin
        if (in_data) begin
          rounded = in_data - 1;
        end else begin
          rounded = in_data;
        end
      end else begin
        if (in_data) begin
          rounded = in_data + 1;
        end else begin
          rounded = in_data;
        end
      end
      rounding_up = 1;
    else begin
      // Default to RTZ
      rounded = in_data;
      rounding_up = 0;
    end
  end else begin
    rounded = in_data;
    inexact = 0;
    cout = 0;
    r_up = 0;
  end

  assign out_data = rounded;
  assign inexact = (roundin || stickyin);
  assign cout = (rounded != in_data);
  assign r_up = rounding_up;

endmodule

output.rtl/copilot_rs_232.sv:
module copilot_rs_232 (
    clock,
    reset_neg,
    tx_datain_ready,
    Present_Processing_Completed,
    tx_datain,
    tx_transmitter,
    tx_transmitter_valid
);
    // Parameters
    parameter HIGH = 1'b1;
    parameter LOW = 1'b0;
    parameter CLOCK_FREQ = 100000000; // 100MHz
    parameter BAUD_RATE = 115200;     // Default baud rate
    parameter REG_INPUT = 1;
    parameter BAUD_ACC_WIDTH = 16;

    // Inputs
    input reset_neg;
    input clock;
    input tx_datain_ready;
    input Present_Processing_Completed;
    input [7:0] tx_datain;

    // Outputs
    output tx_transmitter;
    output tx_transmitter_valid;

    // Internal signals
    reg tx_transmitter;
    reg [4:0] state; // State machine states (Idle=0, Start=1, Data=2-5, Stop=6)
    reg [7:0] output_mux;
    wire baud_pulse;

    // Instantiate the Baud Rate Generator
    baud_rate_generator #(
        .BAUD_ACC_WIDTH(BAUD_ACC_WIDTH),
        .CLOCK_FREQ(CLOCK_FREQ),
        .BAUD_RATE(BAUD_RATE)
    ) baud_gen (
        .clock(clock),
        .reset_neg(reset_neg),
        .enable(tx_transmitter_valid),
        .baud_pulse(baud_pulse)
    );

    always @ (posedge clock or negedge reset_neg) begin
        if (reset_neg == LOW) begin
            state = 0;
            tx_transmitter <= HIGH;
        else if (Present_Processing_Completed == HIGH) begin
            case (state)
                0: state = 1; // Start State
                1: state = 2; // Data State 0
                2: state = 3; // Data State 1
                3: state = 4; // Data State 2
                4: state = 5; // Data State 3
                5: state = 6; // Data State 4
                6: state = 7; // Data State 5
                7: state = 8; // Data State 6
                8: state = 9; // Data State 7
                9: state = 10; // Stop State
            endcase
            tx_transmitter <= HIGH; // Start bit
        else begin
            case (state)
                1: state = 2; // Data State 0
                2: state = 3; // Data State 1
                3: state = 4; // Data State 2
                4: state = 5; // Data State 3
                5: state = 6; // Data State 4
                6: state = 7; // Data State 5
                7: state = 8; // Data State 6
                8: state = 9; // Data State 7
            endcase
            // Assemble Start, Data, and Stop Bits
            tx_transmitter_valid <= 1;
            output_mux = (state < 9) ? (tx_datain) : (tx_datain << 1);
            output_mux = (state < 10) ? (output_mux ^ (tx_datain[7])) : (output_mux | HIGH);
        end else begin
            tx_transmitter_valid <= 0;
        end
    end

endmodule

// Baud Rate Generator Module
module baud_rate_generator #(
    parameter CLOCK_FREQ = 100000000, // 100MHz
    parameter BAUD_RATE = 115200, // Default baud rate
    parameter BAUD_ACC_WIDTH = 16
)
 (
    input clock,
    input reset_neg,
    input enable,
    output reg baud_pulse
);

    // Internal signals
    wire [BAUD_ACC_WIDTH:0] baud_inc;
    reg [BAUD_ACC_WIDTH:0] baud_acc;

    // Calculate the baud increment value
    assign baud_inc = ((BAUD_RATE << (BAUD_ACC_WIDTH - 4)) + (CLOCK_FREQ >> 5)) / (CLOCK_FREQ >> 4);

    // Baud rate generator logic
    always @ (posedge clock or negedge reset_neg) begin
        if (enable) begin
            baud_acc = (baud_acc + baud_inc) & (1 << BAUD_ACC_WIDTH);
            baud_pulse = baud_acc != 0;
        end else begin
            baud_pulse = 0;
        end
    end

endmodule

output.rtl/run_length.sv:
module run_length
#(
    parameter DATA_WIDTH = 8
)
(
    input wire clk,                                 // Clock signal      
    input wire reset_n,                             // Active-low reset signal     
    input wire data_in,                             // Input data stream
    output reg  data_out,                           // Output data to indicate the previous data_in
    output reg [$clog2(DATA_WIDTH):0] run_value,    // Output the run length value 
    output reg valid                                // Output valid flag for run length 
);
    reg [$clog2(DATA_WIDTH):0] run_length;
    reg prev_data_in;

    always @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            run_length   <= 'b0;
            run_value    <= 'b0;
            prev_data_in <= 1'b0;
        end
        else begin
            if (data_in == prev_data_in) begin
                run_length <= run_length + 1;
                if (run_length == DATA_WIDTH) begin
                    valid <= 1;
                    data_out <= prev_data_in;
                    run_length <= 0;
                end
            else begin
                run_length <= 1;
                prev_data_in <= data_in;
                valid <= 0;
            end
        end
    end
end

input.rtl/deinter_block.sv:
module deinter_block #(
    parameter ROW_COL_WIDTH = 16,
    parameter SUB_BLOCKS    = 4,
    parameter DATA_WIDTH    = ROW_COL_WIDTH*ROW_COL_WIDTH,
    parameter OUT_DATA_WIDTH= 16,
    parameter WAIT_CYCLES   = 4
)(
    input  logic clk,
    input  logic rst_n,
    input  logic i_valid,
    input  logic [DATA_WIDTH-1:0] in_data, // Input: 256 bits
    output logic [OUT_DATA_WIDTH-1:0] out_data // Output: 256 bits rearranged
);

localparam CHUNK = 8;
localparam NBW_COUNTER = $clog2(SUB_BLOCKS) + 1;
localparam NBW_COUNTER_SUB_OUT = 2;

localparam OUT_CYCLES = 32;

localparam N_CYCLES = SUB_BLOCKS*DATA_WIDTH/OUT_DATA_WIDTH;
localparam NBW_COUNTER_OUTPUT = $clog2(N_CYCLES);
logic [NBW_COUNTER_OUTPUT-1:0] counter_output;

logic [NBW_COUNTER-1:0] counter_sub_blocks;
logic [NBW_COUNTER_SUB_OUT-1:0] counter_sub_out;

logic [DATA_WIDTH-1:0] in_data_reg [SUB_BLOCKS-1:0];
logic [DATA_WIDTH-1:0] out_data_intra_block [SUB_BLOCKS-1:0];
logic [DATA_WIDTH-1:0] out_data_intra_block_reg [SUB_BLOCKS-1:0];
logic [DATA_WIDTH-1:0] out_data_aux [SUB_BLOCKS-1:0];
logic start_intra;

always_ff @(posedge clk or negedge rst_n ) begin
   if(!rst_n) begin
      counter_sub_blocks <= {NBW_COUNTER{1'b0}};
      start_intra <= 0;
      for(int i = 0; i < SUB_BLOCKS; i++) begin
         in_data_reg[i] <= {DATA_WIDTH{1'b0}};
      end
   end
   else begin
      if(i_valid) begin
         in_data_reg[counter_sub_blocks] <= in_data;

         if(counter_sub_blocks == SUB_BLOCKS) begin
            counter_sub_blocks <= {NBW_COUNTER{1'b0}};
         end
         else begin
            start_intra <= 0;
            counter_sub_blocks <= counter_sub_blocks + 1;
         end
      end
      else if(counter_sub_blocks == SUB_BLOCKS) begin
         start_intra        <= 1;
         counter_sub_blocks <= {NBW_COUNTER{1'b0}};
      end
   end
end

always_ff @(posedge clk or negedge rst_n) begin
   if(!rst_n) begin
      for(int i = 0; i < SUB_BLOCKS; i++)
         out_data_intra_block_reg[i] <= {DATA_WIDTH{1'b0}};
   end
   else begin
      if(start_intra)
         for(int i = 0; i < SUB_BLOCKS; i++) 
            out_data_intra_block_reg[i] <= in_data_reg[i];
   end
end

logic [WAIT_CYCLES-1:0] start_intra_ff;
logic enable_output;

always_ff @(posedge clk or negedge rst_n) begin
   if(!rst_n) begin
      enable_output  <= 0;
      start_intra_ff <= 0;
   end
   else begin
      enable_output <= start_intra_ff[WAIT_CYCLES-1];
      start_intra_ff<= {start_intra_ff[WAIT_CYCLES-1:1],start_intra};
   end
end

always_ff @(posedge clk or negedge rst_n) begin
   if(!rst_n) begin
      for(int i = 0; i < SUB_BLOCKS; i++)
         out_data_aux[i] <= {DATA_WIDTH{1'b0}};
   end
   else begin
      if(start_intra) begin
         for(int i = 0; i < 32; i++) begin
            out_data_aux[0][(i+1)*CHUNK-1-:CHUNK] <= out_data_intra_block_reg[i%4][((i+1)*CHUNK)-1-:CHUNK];
            out_data_aux[1][(i+1)*CHUNK-1-:CHUNK] <= out_data_intra_block_reg[i%4][(((i+1)%OUT_CYCLES+1)*CHUNK)-1-:CHUNK];
            out_data_aux[2][(i+1)*CHUNK-1-:CHUNK] <= out_data_intra_block_reg[i%4][(((i+2)%OUT_CYCLES+1)*CHUNK)-1-:CHUNK];
            out_data_aux[3][(i+1)*CHUNK-1-:CHUNK] <= out_data_intra_block_reg[i%4][(((i+3)%OUT_CYCLES+1)*CHUNK)-1-:CHUNK];
         end
      end
   end
end

always_ff @(posedge clk or negedge rst_n) begin
   if(!rst_n) begin
      out_data        <= {DATA_WIDTH{1'b0}};      
      counter_sub_out <= {NBW_COUNTER_SUB_OUT{1'b0}};
      counter_output  <= {NBW_COUNTER_OUTPUT{1'b0}};     
   end
   else begin
      counter_sub_out <= counter_sub_out + 1;
      counter_output  <= counter_output  + 1;
      out_data        <= out_data_aux[counter_sub_out][((counter_output%(DATA_WIDTH/OUT_DATA_WIDTH) + 1))*OUT_DATA_WIDTH-1-:OUT_DATA_WIDTH];
   end
end

endmodule

output.rtl/deinter_block.sv:
module deinter_block #(
    parameter ROW_COL_WIDTH = 16,
    parameter SUB_BLOCKS    = 4,
    parameter DATA_WIDTH    = ROW_COL_WIDTH*ROW_COL_WIDTH,
    parameter OUT_DATA_WIDTH= 16,
    parameter WAIT_CYCLES   = 4
)(
    input  logic clk,
    input  logic rst_n,
    input  logic [DATA_WIDTH-1:0] in_data, // Input: 256 bits
    output logic [OUT_DATA_WIDTH-1:0] out_data // Output: 256 bits rearranged
);

localparam CHUNK = 8;
localparam NBW_COUNTER = $clog2(SUB_BLOCKS) + 1;
localparam NBW_COUNTER_SUB_OUT = 2;

localparam OUT_CYCLES = 32;

localparam N_CYCLES = SUB_BLOCKS*DATA_WIDTH/OUT_DATA_WIDTH;
localparam NBW_COUNTER_OUTPUT = $clog2(N_CYCLES);
logic [NBW_COUNTER_OUTPUT-1:0] counter_output;

logic [NBW_COUNTER-1:0] counter_sub_blocks;
logic [NBW_COUNTER_SUB_OUT-1:0] counter_sub_out;

logic [DATA_WIDTH-1:0] in_data_reg [SUB_BLOCKS-1:0];
logic [DATA_WIDTH-1:0] out_data_intra_block_reg [SUB_BLOCKS-1:0];
logic [DATA_WIDTH-1:0] out_data_aux [SUB_BLOCKS-1:0];
logic start_intra;

always_ff @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        counter_sub_intra <= {NBW_COUNTER{1'b0}};
        start_intra <= 0;
        for(int i = 0; i < SUB_BLOCKS; i++) begin
            in_data_reg[i] <= {DATA_WIDTH{1'b0}};
        end
    end
    else begin
        if(start_intra) begin
            for(int i = 0; i < 32; i++) begin
                out_data_aux[0][(i+1)*CHUNK-1-:CHUNK] <= out_data_intra_block_reg[i%4][((i+1)*CHUNK)-1-:CHUNK];
            end
        end
        else if(counter_sub_blocks == SUB_BLOCKS) begin
            counter_sub_blocks <= {NBW_COUNTER{1'b0}};
        end
        else begin
            start_intra <= 0;
            counter_sub_blocks <= counter_sub_blocks + 1;
        end
    end
end

always_ff @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        for(int i = 0; i < SUB_BLOCKS; i++) begin
            out_data_intra_block_reg[i] <= {DATA_WIDTH{1'b0}};
        end
        counter_sub_out <= {NBW_COUNTER_SUB_OUT{1'b0}};
    end
    else begin
        if(start_intra) begin
            for(int i = 0; i < 32; i++) begin
                out_data_intra_block_reg[i] <= in_data_reg[i];
            end
        end
        else if(counter_sub_out == SUB_BLOCKS) begin
            start_intra <= 1;
            counter_sub_out <= {NBW_COUNTER_SUB_OUT{1'b0}};
        end
        else begin
            start_intra <= 0;
            counter_sub_out <= counter_sub_out + 1;
        end
    end
end

always_ff @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        out_data        <= {DATA_WIDTH{1'b0}};
        counter_sub_out <= {NBW_COUNTER_SUB_OUT{1'b0}};
        counter_output  <= {NBW_COUNTER_OUTPUT{1'b0}};
    end
    else begin
        out_data        <= out_data_aux[counter_sub_out][((counter_output%(DATA_WIDTH/OUT_DATA_WIDTH))+1)*OUT_DATA_WIDTH-1-:OUT_DATA_WIDTH];
        counter_sub_out <= counter_sub_out + 1;
        counter_output  <= counter_output  + 1;
    end
end

endmodule

input.rtl/inter_block.sv:
module inter_block #(
    parameter ROW_COL_WIDTH = 16,
    parameter SUB_BLOCKS    = 4,
    parameter DATA_WIDTH    = ROW_COL_WIDTH*ROW_COL_WIDTH
)(
    input  logic clk,
    input  logic rst_n,
    input  logic i_valid,
    input  logic [DATA_WIDTH-1:0] in_data, // Input: 256 bits
    output logic [DATA_WIDTH-1:0] out_data // Output: 256 bits rearranged
);

localparam CHUNK = 8;
localparam NBW_COUNTER = $clog2(SUB_BLOCKS) + 1;
localparam NBW_COUNTER_SUB_OUT = 2;
localparam OUT_CYCLES = 32;
localparam NBW_COUNTER_OUTPUT = $clog2(OUT_CYCLES);
logic [NBW_COUNTER_OUTPUT-1:0] counter_output;
logic [NBW_COUNTER-1:0] counter_sub_blocks;
logic [NBW_COUNTER_SUB_OUT-1:0] counter_sub_out;

logic [DATA_WIDTH-1:0] in_data_reg [SUB_BLOCKS-1:0];
logic [DATA_WIDTH-1:0] out_data_intra_block [SUB_BLOCKS-1:0];
