    reg signed [10:0] Gx, Gy;  // Corrected to 10 bits
    reg [7:0] pixel_buffer[0:8]; // 3x3 pixel window
    integer i;

    // Parameters for thresholding
    parameter THRESHOLD = 11'd128;

    // Sliding window logic
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            for (i = 0; i < 9; i = i + 1) begin
                pixel_buffer[i] <= 8'd0;
            end    
        end else if (valid_in) begin
            // Correct buffer indexing for 3x3 window
            Gx <= -pixel_buffer[4] - (pixel_buffer[5] << 1) - pixel_buffer[6] 
                  + pixel_buffer[2] + (pixel_buffer[3] << 1) + pixel_buffer[0];
            Gy <= -pixel_buffer[4] - (pixel_buffer[6] << 1) - pixel_buffer[8] 
                  + pixel_buffer[0] + (pixel_buffer[2] << 1) + pixel_buffer[8];

            // Compute gradient magnitude (simplified as |Gx| + |Gy|)
            edge_out <= ((Gx < 0 ? -Gx : Gx) + (Gy < 0 ? -Gy : Gy)) > THRESHOLD ? 8'd255 : 8'd0;

            // Set valid output
            valid_out <= 1'b1;
        end else begin
            valid_out <= 1'b0;
        end
    end
