    reg [WIDTH-1:0] key;
    reg [N-1:0] i;
    reg [N-1:0] j;

    // FSM: Next state logic
    always @(*) begin
        next_state = state;
        case (state)
            IDLE: begin
                if (start)
                    next_state = SORTING;
            end
            SORTING: begin
                if (i == N)
                    next_state = DONE;
            end
            DONE: begin
                next_state = IDLE;
            end
            default: next_state = IDLE;
        endcase
    end

    // FSM: Main logic
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state         <= IDLE;
            done          <= 0;
            i             <= 0;
            j             <= 0;
            key           <= 0;
        end else begin
            state <= next_state;

            case (state)
                IDLE: begin
                    done <= 0;
                    if (start) begin
                        array[0] <= in_data[0];
                        for (int k = 1; k < N; k = k + 1) begin
                            array[k] <= in_data[(k)*WIDTH: WIDTH-1];
                        end
                        i <= 1;
                        j <= 0;
                    end
                end

                SORTING: begin
                    case (i)
                        0: begin
                            key <= array[0];
                            j <= 0;
                        end
                        1: begin
                            key <= array[1];
                            j <= 1;
                        end
                        default: begin
                            key <= 0;
                            j <= 0;
                        end
                end

                default: begin
                    // Should not get here
                end
            endcase
        end
    end

    // Sort complete
    always begin
        done <= 1;
        for (int m = 0; m < N; m = m + 1) begin
            out_data[m*WIDTH: WIDTH-1] <= array[m];
        end
    end

