module static_branch_predict (

  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o,
  output logic [31:0] predict_confidence_o,
  output logic [31:0] predict_exception_o,
  output logic [31:0] predict_branch_type_o,
  output logic [31:0] predict_branch_offset_o;
  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cb_type;
  logic [31:0] imm_cj_type;

  logic [31:0] branch_imm;

  logic [31:0] instr;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  logic instr_b_taken;

  localparam OPCODE_BRANCH = 7'h63;
  localparam OPCODE_JAL    = 7'h6F;
  localparam OPCODE_JALR   = 7'h67;

  assign instr = fetch_rdata_i;
  assign reg_addr = register_addr_i;

  assign imm_jal_type = {{12{instr[31]}}, instr[19:12], instr[20], instr[30:25], instr[11:8], 1'b0 };
  assign imm_jalr_type = {{20{instr[31]}}, instr[31:20]}+reg_addr;
  assign imm_b_type = { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };

  assign imm_cj_type = { {20{instr[12]}}, instr[12], instr[8], instr[10:9], instr[6], instr[7],
    instr[2], instr[11], instr[5:3], 1'b0 };

  assign imm_cb_type = { {23{instr[12]}}, instr[12], instr[6:5], instr[2], instr[11:10],
    instr[4:3], 1'b0 };

  assign instr_b    = instr[6:0] == OPCODE_BRANCH;
  assign instr_jal  = instr[6:0] == OPCODE_JAL;
  assign instr_jalr = instr[6:0] == OPCODE_JALR;

  assign instr_cb = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b110) | (instr[15:13] == 3'b111));
  assign instr_cj = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b101) | (instr[15:13] == 3'b001));

  always_comb begin
    branch_imm = imm_b_type;

    case(1'b1)
      instr_jal  : branch_imm = imm_jal_type;
      instr_jalr : branch_imm = imm_jalr_type;
      instr_b    : branch_imm = imm_b_type;
      instr_cj   : branch_imm = imm_cj_type;
      instr_cb   : branch_imm = imm_cb_type;
      default    : branch_imm = 0;
    endcase
  end

  assign predict_confidence_o = branch_imm[31] ? (instr_jal || instr_jalr) ? 100 : (instr_b ? 90 : 50) : 0;

  assign predict_exception_o = (fetch_pc_i[1:0] != 2'b00);

  assign predict_branch_type_o = case(
    instr_jalr: 3'b010,
    instr_jal: 3'b001,
    instr_b: 3'b011,
    instr_cj: 3'b100,
    instr_cb: 3'b101,
    default: 3'b000
  );

  assign predict_branch_offset_o = branch_imm;

  assign predict_branch_pc_o = fetch_pc_i + branch_imm;

  assign predict_target_address_o = predict_branch_pc_o;

  assign instr_b_taken = (instr_b & (imm_b_type[31] == 1)) | (instr_cb & (imm_cb_type[31] == 0));
  assign predict_branch_taken_o = (instr_b_taken && (predict_confidence_o >= 50)) || (instr_cj && (predict_confidence_o >= 50));
endmodule

module static_branch_predict (

  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o
);
  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;

  logic [31:0] branch_imm;

  logic [31:0] instr;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  logic instr_b_taken;

  assign instr = fetch_rdata_i;
  assign reg_addr = register_addr_i;

  // Decode instruction type and calculate immediate
  if (instr[6:0] == 7'h6F) begin
    instr_jal = 1;
    branch_imm = imm_jal_type;
  elsif (instr[6:0] == 7'h67) begin
    instr_jalr = 1;
    branch_imm = imm_jalr_type;
  elsif (instr[6:0] == 7'h63) begin
    instr_b = 1;
    branch_imm = imm_b_type;
  elsif (instr[31:0] == 7'h20 || instr[31:0] == 7'h1F) begin
    instr_cj = 1;
    branch_imm = imm_cj_type;
  else if (instr[31:0] == 7'h21) begin
    instr_cb = 1;
    branch_imm = imm_cb_type;
  end

  // Set branch_taken based on instruction type and immediate
  instr_b_taken = 0;
  if (instr_jal || instr_jalr || instr_cj) begin
    predict_branch_taken_o = 1;
  elsif (instr_b || instr_cb) begin
    if (branch_imm[31] == 1) begin
      predict_branch_taken_o = 1;
    end
  end

  // Calculate predicted branch target address
  predict_branch_pc_o = branch_imm + fetch_pc_i;

module static_branch_predict(
  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o,

  // Additional outputs
  output logic [7:0]  predict_confidence_o,   // Confidence level in prediction
  output logic        predict_exception_o,    // Exception/misalignment detection
  output logic [2:0]  predict_branch_type_o,  // Type of branch
  output logic [31:0] predict_branch_offset_o // Calculated branch offset
);

  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;
  logic [31:0] instr;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  logic instr_b_taken;

  // Assign instruction type
  instr = fetch_rdata_i;
  instr_jal = (instr[6:0] == 7'h6F);
  instr_jalr = (instr[6:0] == 7'h67);
  instr_b = (instr[6:0] == 7'h63);
  instr_cj = (instr[6:0] == 7'h66); // Assuming CJ opcode is 0x66
  instr_cb = (instr[6:0] == 7'h64); // Assuming CB opcode is 0x64

  // Calculate imm values
  imm_jal_type = {
    {12{instr[31]}},
    instr[19:12],
    instr[20],
    instr[30:21],
    1'b0
  };

  imm_jalr_type = {
    {{20{instr[31]}}, instr[31:20]} + register_addr_i
  };

  imm_b_type = {
    {{19{instr[31]}}, instr[31],
     instr[7],
     instr[30:25],
     instr[11:8],
     1'b0}
  };

  imm_cj_type = {
    {{20{instr[12]}}, instr[12],
     instr[8],
     instr[10:9],
     instr[6],
     instr[7],
     instr[2],
     instr[11],
     instr[5:3],
     1'b0}
  };

  imm_cb_type = {
    {{23{instr[12]}}, instr[12],
     instr[6:5],
     instr[2],
     instr[11:10],
     instr[4:3],
     1'b0}
  };

  // Calculate confidence levels
  predict_confidence_o = 50;
  if (instr_b) {
    if (imm_b_type[31] == 1) {
      predict_confidence_o = 90;
    }
  }
  else if (instr_cj || instr_cb) {
    predict_confidence_o = 90;
  }
  else if (instr_jal || instr_jalr) {
    predict_confidence_o = 100;
  }
  else if (!fetch_valid_i) {
    predict_confidence_o = 0;
  }

  // Set branch taken flag
  predict_branch_taken_o = (predict_confidence_o > 50);

  // Calculate target address
  predict_branch_offset_o = 0;
  if (instr_jal) {
    predict_branch_offset_o = imm_jal_type;
  }
  else if (instr_jalr) {
    predict_branch_offset_o = imm_jalr_type;
  }
  else if (instr_b) {
    predict_branch_offset_o = imm_b_type;
  }
  else if (instr_cj || instr_cb) {
    predict_branch_offset_o = imm_cj_type;
  }

  // Exception detection
  predict_exception_o = 0;
  // Implement exception detection logic here if needed
endmodule

