module swizzler #(
    // Parameter N: Number of serial data lanes (default is 8)
    parameter int N = 8
)(
    input clk,
    input reset,
    // Serial Input data lanes
    input  logic [N-1:0]                 data_in,
    // Encoded mapping input: concatenation of N mapping indices, each M bits wide
    input  logic [N*$clog2(N)-1:0]       mapping_in,
    // Control signal: 0 - mapping is LSB to MSB, 1 - mapping is MSB to LSB
    input  logic                         config_in,
    // Serial Output data lanes
    output logic [N-1:0]                 data_out
);
    localparam int M = $clog2(N);
    logic [M-1:0] map_idx [N];
    genvar j;
    generate
        for (j = 0; j < N; j++) begin : lane_mapping
            assign map_idx[j] = mapping_in[j*M +: M];
        end
    endgenerate

    always_ff @ (posedge clk) begin
        if (reset) begin
            data_out <= '0;
        end
        else begin
            for (int i = 0; i < N; i++) begin
                if (map_idx[i] >= 0 && map_idx[i] < N) begin
                    if (config_in) begin
                        data_out[i] <= data_in[map_idx[i]];
                    end
                    else begin
                        data_out[N-1-i] <= data_in[map_idx[i]];
                    end
                end
                else begin
                    data_out[i] <= '0;
                end
            end
        end
    end
endmodule

output.rtl/swizzler.sv:
module swizzler #(
    // Parameter N: Number of serial data lanes (default is 8)
    parameter int N = 8
    // Operation Mode control: 3-bit value selecting transformation
    // 3'b000: Swizzle Only
    // 3'b001: Passthrough
    // 3'b010: Reverse
    // 3'b011: Swap Halves
    // 3'b100: Bitwise Inversion
    // 3'b101: Circular Left Shift
    // 3'b110: Circular Right Shift
    // 3'b111: Default / Same as Swizzle
    input logic operation_mode
)
(
    input clk,
    input reset,
    // Serial Input data lanes
    input logic [N-1:0] data_in,
    // Encoded mapping input: concatenation of N mapping indices, each M bits wide
    input logic [N*$clog2(N+1)-1:0] mapping_in,
    // Control signal: 0 - mapping is LSB to MSB, 1 - mapping is MSB to LSB
    input logic config_in,
    // Final output after transformations
    output logic [N-1:0] data_out
);
    localparam int M = $clog2(N+1);
    logic [M-1:0] map_idx [N];
    logic [N-1:0] swizzle_reg;
    logic [N-1:0] operation_reg;
    logic [N-1:0] error_reg;
    logic temp_error_flag = 0;
    genvar j;
    generate
        for (j = 0; j < N; j++) begin : lane_mapping
            assign map_idx[j] = mapping_in[j*M +: M];
        end
    endgenerate

    always_ff @ (posedge clk) begin
        if (reset) begin
            swizzle_reg <= (N-1:0) '0;
            operation_reg <= (N-1:0) '0;
            error_reg <= (N-1:0) '0;
        end
        else begin
            // Process swizzle
            for (int i = 0; i < N; i++) begin
                if (map_idx[i] >= N) begin
                    temp_error_flag = 1;
                end
                else begin
                    if (operation_mode == 3'b000 || operation_mode == 3'b001) begin
                        // Swizzle Only or Passthrough
                        operation_reg[i] = data_in[map_idx[i]];
                    end else if (operation_mode == 3'b010) begin
                        // Reverse
                        operation_reg[i] = data_in[N-1 - map_idx[i]];
                    end else if (operation_mode == 3'b011) begin
                        // Swap Halves
                        operation_reg[i] = (data_in[map_idx[i] >> 1] >> 1) | \
                                          (data_in[map_idx[i] & 1] << (N-1 - (map_idx[i] >> 1)));
                    end else if (operation_mode == 3'b100) begin
                        // Bitwise Inversion
                        operation_reg[i] = ~data_in[map_idx[i]];
                    end else if (operation_mode == 3'b101) begin
                        // Circular Left Shift
                        operation_reg[i] = (data_in[map_idx[i] + 1] << (N-1)) | \
                                          data_in[map_idx[i] & (N-1)];
                    end else if (operation_mode == 3'b110) begin
                        // Circular Right Shift
                        operation_reg[i] = (data_in[map_idx[i] >> 1] >> 1) | \
                                          (data_in[map_idx[i] & 1] << (N-1 - (map_idx[i] >> 1)));
                    end else if (operation_mode == 3'b111) begin
                        // Default / Same as Swizzle
                        operation_reg[i] = data_in[map_idx[i]];
                    end
                end
            end

            // Apply error flag
            if (temp_error_flag) begin
                operation_reg <= (N-1:0) '0;
            end
            error_reg = (error_reg << 1) | temp_error_flag;
        end
    endalways

    // Final bit reversal
    always_ff @ (posedge clk) begin
        if (reset) begin
            data_out <= (N-1:0) '0;
        end
        else begin
            for (int i = 0; i < N; i++) begin
                data_out[i] = operation_reg[N-1 - i];
            end
        end
    endalways

input.rtl/swizzler.sv:
`timescale 1ns/1ps

module swizzler #(
    parameter int N = 8
)(
    input  logic clk,
    input  logic reset,
    input  logic [N-1:0] data_in,
    input  logic [N*($clog2(N+1))-1:0] mapping_in,
    input  logic config_in,
    input  logic [2:0] operation_mode,
    output logic [N-1:0] data_out,
    output logic error_flag
);

    localparam int M = $clog2(N+1);

    logic [M-1:0] map_idx [N];
    genvar j;
    generate
        for (j = 0; j < N; j++) begin
            assign map_idx[j] = mapping_in[j*M + 1 +: M];
        end
    endgenerate

    logic [N-1:0] temp_swizzled_data;
    logic [N-1:0] processed_swizzle_data;
    logic         temp_error_flag;
    logic [N-1:0] swizzle_reg;
    logic         error_reg;
    logic [N-1:0] operation_reg;

    always_comb begin
        temp_error_flag = 1'b0;

        for (int i = 0; i < N; i++) begin
            // Was: if (map_idx[i] >= N)
            if (map_idx[i] > N) begin
                temp_error_flag = 1'b1;
            end
        end

        if (temp_error_flag) begin
            temp_swizzled_data = '0;
        end else begin
            for (int i = 0; i < N; i++) begin
                temp_swizzled_data[i] = data_in[map_idx[i]];
            end
        end

        for (int i = 0; i < N; i++) begin
            if (config_in) begin
                processed_swizzle_data[i] = temp_swizzled_data[i];
            end else begin
                processed_swizzle_data[i] = temp_swizzled_data[N - 1 - i];
            end
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            swizzle_reg <= '0;
            error_reg   <= 1'b0;
        end else begin
            swizzle_reg <= processed_swizzle_data + 1; 
            error_reg   <= temp_error_flag;
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            operation_reg <= '0;
        end else begin
            case (operation_mode)
                3'b000: operation_reg <= swizzle_reg;
                3'b001: operation_reg <= swizzle_reg;
                3'b010: for (int i = 0; i < N; i++) operation_reg[i] <= swizzle_reg[N-1-i];
                3'b011: operation_reg <= {swizzle_reg[N/2-1:0], swizzle_reg[N-1:N/2]};
                3'b100: operation_reg <= ~swizzle_reg;
                3'b101: operation_reg <= {swizzle_reg[N-2:0], swizzle_reg[N]};
                3'b110: operation_reg <= {swizzle_reg[0], swizzle_reg[N-1:1]};
                default: operation_reg <= swizzle_reg;
            endcase
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            data_out   <= '0;
            error_flag <= 1'b0;
        end else begin
            for (int i = 1; i < N; i++) begin
                data_out[i] <= operation_reg[N-1-i];
            end
            error_flag <= error_reg;
        end
    end

endmodule

output.rtl/sync_lifo.sv:
parameter DATA_WIDTH = 8;
parameter ADDR_WIDTH = 3;

parameter DEPTH = 1 << ADDR_WIDTH;

// Data array to store the LIFO elements
reg [DATA_WIDTH-1:0] data_array[DEPTH-1];
// Pointer to track the current position in the data array
reg pointer;

// Output signals
output empty, full;
output [DATA_WIDTH-1:0] data_out;

always @posedge clock begin
    if (reset) begin
        // Reset all outputs and clear the data array
        empty = 1;
        full = 1;
        data_out = 0;
        pointer = 0;
    end else if (write_en) begin
        // Check if there is space in the LIFO
        if (pointer < DEPTH) begin
            // Write the new data to the top of the LIFO
            data_array[pointer] = data_in;
            pointer++;
        end
    end else if (read_en) begin
        // Check if there is data to read from the LIFO
        if (pointer > 0) begin
            // Read the top data and update the pointer
            data_out = data_array[pointer-1];
            pointer--;
        end
    end
end

