            end
            3'b011: begin
                data_reg_rx <= data_in[63:0];
                bit_count_rx <= 7'd63;
            end
            3'b100: begin
                data_reg_rx <= data_in[63:0];
                bit_count_rx <= 7'd63;
            end
            default: begin
                data_reg_rx <= 64'h0;
                bit_count_rx <= 7'd0;
            end
        endcase
    end else if (bit_count > 7'h0) begin
        data_reg_rx <= data_reg_rx >> 1;
        bit_count_rx <= bit_count_rx - 1;
        parity_out <= parity; // Transmit the parity bit
    end
end

// Set the done signal when transmission is complete
always @(posedge clock or negedge reset_n) begin 
    if (!reset_n) begin
        done = 1'b1;
        case (sel)
            3'b000: begin
                data_reg_rx <= {56'h0, data_in[7:0]};
                bit_count_rx <= 7'd7;
            end
            3'b001: begin
                data_reg_rx <= {48'h0, data_in[15:0]};
                bit_count_rx <= 7'd15;
            end
            3'b010: begin
                data_reg_rx <= {40'h0, data_in[31:0]};
                bit_count_rx <= 7'd31;
            end
            3'b011: begin
                data_reg_rx <= data_in[63:0];
                bit_count_rx <= 7'd63;
            end
            3'b100: begin
                data_reg_rx <= data_in[63:0];
                bit_count_rx <= 7'd63;
            end
            default: begin
                data_reg_rx <= 64'h0;
                bit_count_rx <= 7'd0;
            end
        endcase
    end else if (bit_count > 7'h0) begin
        data_reg_rx <= data_reg_rx >> 1;
        bit_count_rx <= bit_count_rx - 1;
    end
    done <= 1'b0;
end

// Set the done signal when transmission is complete
always @(posedge clock or negedge reset_n) begin
    if (!reset_n) begin
        done_tx = 1'b1;
        case (sel)
            3'b000: begin
                data_reg <= {56'h0, data_in[7:0]};
                bit_count <= 7'd7;
            end
            3'b001: begin
                data_reg <= {48'h0, data_in[15:0]};
