module thermostat(
    input wire [5:0] i_temp_feedback,
    input wire i_fan_on,
    input wire i_enable,
    input wire i_fault,
    input wire i_rst,
    output reg [2:0] o_state,
    output reg [1:0] o_heater_full, o_heater_medium, o_heater_low,
    output reg [1:0] o_aircon_full, o_aircon_medium, o_aircon_low,
    output reg o_fan
);

    reg current_state = 3'b000; // AMBIENT

    always @posedge i_rst) begin
        o_state = 3'b000;
        o_heater_full = 0;
        o_heater_medium = 0;
        o_heater_low = 0;
        o_aircon_full = 0;
        o_aircon_medium = 0;
        o_aircon_low = 0;
        o_fan = 0;
    end

    always @posedge i_rst or @* i_fault or @* i_enable) begin
        if (i_fault) begin
            o_state = 3'b000;
            o_heater_full = 0;
            o_heater_medium = 0;
            o_heater_low = 0;
            o_aircon_full = 0;
            o_aircon_medium = 0;
            o_aircon_low = 0;
            o_fan = 0;
        else if (i_enable) begin
            o_heater_full = 0;
            o_heater_medium = 0;
            o_heater_low = 0;
            o_aircon_full = 0;
            o_aircon_medium = 0;
            o_aircon_low = 0;
        else if (o_state == 3'b000) begin // AMBIENT
            if (i_temp_feedback[5] == 1) begin
                o_state = 3'b011;
                o_heater_full = 1;
            else if (i_temp_feedback[4] == 1) begin
                o_state = 3'b010;
                o_heater_medium = 1;
            else if (i_temp_feedback[3] == 1) begin
                o_state = 3'b001;
                o_heater_low = 1;
            else if (i_temp_feedback[2] == 1) begin
                o_state = 3'b110;
                o_aircon_low = 1;
            else if (i_temp_feedback[1] == 1) begin
                o_state = 3'b101;
                o_aircon_medium = 1;
            else if (i_temp_feedback[0] == 1) begin
                o_state = 3'b111;
                o_aircon_full = 1;
            end
        else if (o_state == 3'b011) begin // HEAT_FULL
            if (i_temp_feedback[5] == 1) begin
                o_state = 3'b011;
            else if (i_temp_feedback[4] == 1) begin
                o_state = 3'b010;
                o_heater_medium = 1;
            else if (i_temp_feedback[3] == 1) begin
                o_state = 3'b001;
                o_heater_low = 1;
            else begin
                o_state = 3'b110;
                o_aircon_low = 1;
            end
        else if (o_state == 3'b010) begin // HEAT MED
            if (i_temp_feedback[5] == 1) begin
                o_state = 3'b010;
            else if (i_temp_feedback[4] == 1) begin
                o_state = 3'b001;
                o_heater_low = 1;
            else begin
                o_state = 3'b110;
                o_aircon_low = 1;
            end
        else if (o_state == 3'b001) begin // HEAT_LOW
            if (i_temp_feedback[5] == 1) begin
                o_state = 3'b001;
            else begin
                o_state = 3'b110;
                o_aircon_low = 1;
            end
        else if (o_state == 3'b110) begin // COOL_LOW
            if (i_temp_feedback[2] == 1) begin
                o_state = 3'b110;
            else if (i_temp_feedback[1] == 1) begin
                o_state = 3'b101;
                o_aircon_medium = 1;
            else if (i_temp_feedback[0] == 1) begin
                o_state = 3'b111;
                o_aircon_full = 1;
            else begin
                o_state = 3'b000;
            end
        else if (o_state == 3'b101) begin // COOL_MED
            if (i_temp_feedback[2] == 1) begin
                o_state = 3'b101;
            else if (i_temp_feedback[1] == 1) begin
                o_state = 3'b100;
                o_aircon_high = 1;
            else if (i_temp_feedback[0] == 1) begin
                o_state = 3'b000;
            else begin
                o_state = 3'b000;
            end
        else if (o_state == 3'b100) begin // COOL_FULL
            if (i_temp_feedback[2] == 1) begin
                o_state = 3'b100;
            else begin
                o_state = 3'b000;
            end
        else begin
            o_state = 3'b000;
        end
    end

    // Fan control
    o_fan = i_fan_on || (o_heater_full || o_heater_medium || o_heater_low || o_aircon_full || o_aircon_medium || o_aircon_low);

endmodule

output.rtl/ttc_counter_lite.sv:
module ttc_counter_lite(
    input clock,
    input reset,
    input axi_addr,
    input axi_wdata,
    input axi_write_en,
    input axi_read_en,
    output axi_rdata,
    output interrupt
);

    // Initialize parameters
    parameter MATCH_VALUE = 65535;
    parameter RELOAD_VALUE = 65535;

    // Register map
    reg [31:0] count;          // Lower 16 bits used
    reg [31:0] match_value;    // Match value register
    reg [31:0] reload_value;   // Reload value register
    reg [31:0] control;        // Control register
    reg [31:0] status;         // Status register

    // Clock control
    clock controlclk;

    // Counter logic
    integer count_val = 0;

    // Match detection flag
    reg match_flag = 0;

    // Always blocks
    always clocked (
        controlclk = enable ? 1 : 0
    ) begin
        if (reset) 
            count_val = 0;
        else if (enable) 
            count_val = (count_val + 1) % 65536;
        end

        // Match detection
        if (count_val == match_value) 
            match_flag = 1;
        end

        // Interval mode reload
        if (interval_mode && match_flag) 
            reload_value = reload_value;
        end

        // Interrupt generation
        if (interrupt_enable && match_flag) 
            interrupt = 1;
        end

        // AXI operations
        if (axi_write_en) 
            match_value = axi_wdata;
        end
        if (axi_read_en) 
            count = count_val;
            reload_value = reload_value;
            status = (interrupt ? 1 : 0);
        end
    end

    // AXI data output
    axi_rdata = count;

    // Reset initialization
    initial begin
        $write(count, 0);
        $write(match_value, MATCH_VALUE);
        $write(reload_value, RELOAD_VALUE);
        $write(control, 0);
        $write(status, 0);
        $finish;
    end

    // Control signals
    enable = 0;
    interval_mode = 0;
    interrupt_enable = 0;
    control[2:0] = enable;
    control[3] = interval_mode;
    control[4:0] = interrupt_enable;
endmodule

output.rtl/unpack_one_hot.v:
module unpack_one_hot(
    input sign,
    input size,
    input [2:0] one_hot_selector,
    input [255:0] source_reg,
    output [511:0] destination_reg
);
    integer i;
    parameter CHUNK_WIDTH = 8;
    parameter DEST_WIDTH = 512;

    // Initialize destination register to zero
    destination_reg <= 0;

    // Determine chunk size based on one-hot selector
    integer chunk_size;
    case (one_hot_selector)
    3'b001: chunk_size = 1;
    3'b010: chunk_size = 2;
    3'b100: chunk_size = size ? 8 : 4;
    default: chunk_size = 256;
    endcase

    // Determine destination width per chunk
    integer dest_chunk_size;
    case (one_hot_selector)
    3'b001: dest_chunk_size = 8;
    3'b010: dest_chunk_size = 8;
    3'b100: dest_chunk_size = size ? 16 : 8;
    default: dest_chunk_size = 256;
    endcase

    // Unpack data
    for (i = 0; i < 256; i += chunk_size) begin
        // Extract chunk from source register
        local [7:0] chunk;
        chunk = source_reg[i + 7: i];

        // Convert chunk to appropriate width
        local [dest_chunk_size - 1:0] unpacked;
        unpacked = chunk;

        // Apply sign extension
        if (sign) begin
            unpacked = { ( (chunk[0] & 1) ? ( (8 - dest_chunk_size) : (4 - dest_chunk_size) ) : 0 ) 
                        << (dest_chunk_size - 1), 
                        unpacked };
        end

        // Write to destination register
        destination_reg[i + dest_chunk_size - 1: i] = unpacked;
    endfor
endmodule

