// State declarations
enum state_t state = state.IDLE;
enum state_t next_state;

// State transitions
always next_state begin
    case (state, item_button, cancel)
        state.IDLE & !item_button & !cancel => next_state = state.IDLE;
        state.IDLE & item_button & !cancel => next_state = state.ITEM_SELECTION;
        state.IDLE & item_button & cancel => next_state = state.RETURN_MONEY;
        state.ITEM_SELECTION & !item_selected => next_state = state.IDLE;
        state.ITEM_SELECTION & item_selected & !cancel => next_state = state.PAYMENT_VALIDATION;
        state.ITEM_SELECTION & item_selected & cancel => next_state = state.RETURN_MONEY;
        state.PAYMENT_VALIDATION & !coin_input => next_state = state.PAYMENT_VALIDATION;
        state.PAYMENT_VALIDATION & coin_input => next_state = state.PAYMENT_VALIDATION;
        state.PAYMENT_VALIDATION & (item_price > coins_accumulated) => next_state = state.PAYMENT_VALIDATION;
        state.PAYMENT_VALIDATION & (item_price <= coins_accumulated) => next_state = state.DISPENSING_ITEM;
        state.PAYMENT_VALIDATION & cancel => next_state = state.RETURN_MONEY;
        state.PAYMENT_VALIDATION & error => next_state = state.RETURN_MONEY;
        state.DISPENSING_ITEM & !dispense_item => next_state = state.DISPENSING_ITEM;
        state.DISPENSING_ITEM & dispense_item => next_state = state.RETURNCHANGE;
        state.RETURNCHANGE & !return_change => next_state = state.RETURNCHANGE;
        state.RETURNCHANGE & return_change => next_state = state.IDLE;
        state.RETURN_MONEY & !return_money => next_state = state.RETURN_MONEY;
        state.RETURN_MONEY & return_money => next_state = state.IDLE;
    endcase
end

// State machine transitions
always @posedge clock begin
    if (rst) 
        state = state.IDLE;
        next_state = state.IDLE;
    else 
        next_state = state.next_state;
    end
end

// Item selection validation
always @posedge clock begin
    if (item_button & !item_selected) 
        state = state.IDLE;
        next_state = state.IDLE;
    else 
        state = state.ITEM_SELECTION;
        next_state = state.ITEM_SELECTION;
    end
end

// Coin validation
always @posedge clock begin
    if (coin_input & !valid_coin) 
        state = state.IDLE;
        next_state = state.IDLE;
    else 
        state = state.PAYMENT_VALIDATION;
        next_state = state.PAYMENT_VALIDATION;
    end
end

// Change calculation
always @posedge clock begin
    if (change_amount > 0) 
        state = state.RETURNCHANGE;
        next_state = state.RETURNCHANGE;
    else 
        state = state.IDLE;
        next_state = state.IDLE;
    end
end

// Error handling
always @posedge clock begin
    if (error) 
        state = state.RETURN_MONEY;
        next_state = state.RETURN_MONEY;
    else 
        state = state.IDLE;
        next_state = state.IDLE;
    end
end

// Output assignments
always @posedge clock begin
    if (dispense_item) 
        dispense_item = 1;
        dispense_item.next_state = state.DISPENSING_ITEM;
    else 
        dispense_item = 0;
    end
    if (return_change) 
        return_change = 1;
        return_change.next_state = state.RETURNCHANGE;
    else 
        return_change = 0;
    end
    if (error) 
        error = 1;
        error.next_state = state.RETURN_MONEY;
    else 
        error = 0;
    end
    if (return_money) 
        return_money = 1;
        return_money.next_state = state.IDLE;
    else 
        return_money = 0;
    end
end

// Initial state assignments
state = state.IDLE;
next_state = state.IDLE;

output.rtl/vga_controller.sv:
module vga_controller(
    input clock,
    input reset,
    input color_in,
    output hsync,
    output vsync,
    output [7:0] red, green, blue,
    output [9:0] next_x, next_y
);

    // Horizontal State Machine
    reg [3:0] h_state = 0;
    // Vertical State Machine
    reg [3:0] v_state = 0;
    // Counters
    reg [9:0] h_counter = 0;
    reg [9:0] v_counter = 0;
    // RGB Signals
    reg [7:0] red_val = 0;
    reg [7:0] green_val = 0;
    reg [7:0] blue_val = 0;

    // Horizontal State Transitions
    always_ff (posedge clock or reset) begin
        if (reset) begin
            h_state = 0;
            h_counter = 0;
            v_state = 0;
            v_counter = 0;
            line_done = 0;
            red_val = 0;
            green_val = 0;
            blue_val = 0;
        else begin
            case (h_state)
                0: h_counter = 1; h_state = 1; // Active
                1: if (h_counter == H_ACTIVE) begin
                    h_counter = 0; h_state = 2; // Front Porch
                    line_done = 1;
                end else h_counter++;
                2: if (h_counter == H_FRONT + H_PULSE) begin
                    h_counter = 0; h_state = 3; // Back Porch
                    line_done = 1;
                end else h_counter++;
                3: if (h_counter == H_BACK) begin
                    h_counter = 0; h_state = 0; // Active
                    line_done = 0;
                end else h_counter++;
                default: h_counter++;
            endcase
        end
    end

    // Vertical State Transitions
    always_ff (posedge clock or reset) begin
        if (reset) begin
            v_state = 0;
            v_counter = 0;
        else begin
            case (v_state)
                0: v_counter = 1; v_state = 1; // Active
                1: if (v_counter == V_ACTIVE) begin
                    v_counter = 0; v_state = 2; // Front Porch
                end else v_counter++;
                2: if (v_counter == V_FRONT + V_PULSE) begin
                    v_counter = 0; v_state = 3; // Back Porch
                end else v_counter++;
                3: if (v_counter == V_BACK) begin
                    v_counter = 0; v_state = 0; // Active
                end else v_counter++;
                default: v_counter++;
            endcase
        end
    end

    // RGB Signal Assignment
    always_ff (posedge clock or reset) begin
        case (h_state)
            0: red = (color_in[7:5] << 5) | 0b00000000000;
               green = (color_in[4:2] << 5) | 0b00000000000;
               blue = (color_in[1:0] << 6) | 0b000000000000000;
            2: red = 0b00000000000;
               green = 0b00000000000;
               blue = 0b00000000000;
            default: red = 0b00000000000;
                     green = 0b00000000000;
                     blue = 0b00000000000;
        endcase
    end

    // Sync Signals
    hsync = (h_state == 1) ? 1 : 0;
    vsync = (v_state == 1) ? 1 : 0;

    // Blank Signal
    blank = !hsync & !vsync;
endmodule

module vga_controller (
    input logic clock,      // 25 MHz
    input logic reset,      // Active high
    input logic [7:0] color_in, // Pixel color data (RRRGGGBB)
    output logic [9:0] next_x,  // x-coordinate of NEXT pixel that will be drawn
    output logic [9:0] next_y,  // y-coordinate of NEXT pixel that will be drawn
    output logic hsync,     // HSYNC (to VGA connector)
    output logic vsync,     // VSYNC (to VGA connector)
    output logic [7:0] red, // RED (to resistor DAC VGA connector)
    output logic [7:0] green, // GREEN (to resistor DAC to VGA connector)
    output logic [7:0] blue, // BLUE (to resistor DAC to VGA connector)
    output logic sync,      // SYNC to VGA connector
    output logic clk,       // CLK to VGA connector
    output logic blank,      // BLANK to VGA connector
    output logic [7:0] h_state, // States of Horizontal FSM
    output logic [7:0] v_state, // States of Vertical FSM
);

    parameter logic [9:0] H_ACTIVE  =  10'd640;
    parameter logic [9:0] H_FRONT   =  10'd16;
    parameter logic [9:0] H_PULSE   =  10'd96;
    parameter logic [9:0] H_BACK    =  10'd48;
    parameter logic [9:0] V_ACTIVE  =  10'd480;
    parameter logic [9:0] V_FRONT   =  10'd10;
    parameter logic [9:0] V_PULSE   =  10'd2;
    parameter logic [9:0] V_BACK    =  10'd33;
    parameter logic LOW   = 1'b0;
    parameter logic HIGH  = 1'b1;
    parameter logic [7:0] H_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] H_FRONT_STATE   = 8'd1;
    parameter logic [7:0] H_PULSE_STATE   = 8'd2;
    parameter logic [7:0] H_BACK_STATE    = 8'd3;
    parameter logic [7:0] V_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] V_FRONT_STATE   = 8'd1;
    parameter logic [7:0] V_PULSE_STATE   = 8'd2;
    parameter logic [7:0] V_BACK_STATE    = 8'd3;


    logic line_done;
    logic [9:0] h_counter;
    logic [9:0] v_counter;

    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            h_counter   <= 10'd0;
            v_counter   <= 10'd0;
            h_state     <= H_ACTIVE_STATE;
            v_state     <= V_ACTIVE_STATE;
            line_done   <= LOW;
        end
        else begin
            case (h_state)
                H_ACTIVE_STATE: begin
                    h_counter <= h_counter + 1;
                    if (h_counter == H_ACTIVE-1) begin
                        hsync <= HIGH;
                        h_state <= H_FRONT_STATE;
                    end
                end
                H_FRONT_STATE: begin
                    line_done <= HIGH;
                    if (v_counter == H_FRONT-1) begin
                        hsync <= HIGH;
                        h_state <= H_PULSE_STATE;
                    end
                end
                H_PULSE_STATE: begin
                    h_counter <= h_counter + 1;
                    if (h_counter == H_PULSE-1) begin
                        hsync <= LOW;
                        h_state <= H_BACK_STATE;
                    end
                end
                H_BACK_STATE: begin
                    h_counter <= h_counter + 1;
                    if (h_counter == H_BACK-1) begin
                        hsync <= HIGH;
                        h_state <= H_ACTIVE_STATE;
                        line_done <= LOW;
                    end
                end
            endcase

            case (v_state)
                V_ACTIVE_STATE: begin
                    v_counter <= v_counter + 1;
                    if (v_counter == V_ACTIVE-1) begin
                        vsync <= HIGH;
                        v_state <= V_FRONT_STATE;
                    end
                end
                V_FRONT_STATE: begin
                    line_done <= HIGH;
                    if (h_counter == V_FRONT-1) begin
                        vsync <= HIGH;
                        v_state <= V_PULSE_STATE;
                    end
                end
                V_PULSE_STATE: begin
                    v_counter <= v_counter + 1;
                    if (v_counter == V_PULSE-1) begin
                        vsync <= LOW;
                        v_state <= V_BACK_STATE;
                    end
                end
                V_BACK_STATE: begin
                    v_counter <= v_counter + 1;
                    if (v_counter == V_BACK-1) begin
                        vsync <= HIGH;
                        v_state <= V_ACTIVE_STATE;
                        line_done <= LOW;
                    end
                end
            endcase
        end
    end


    assign sync = 1'b0;
    assign blank = hsync & vsync;

    assign next_x = (h_state == H_ACTIVE_STATE) ? h_counter : 10'd0;
    assign next_y = (v_state == V_ACTIVE_STATE) ? v_counter : 10'd0;

    case (h_state & v_state)
        H_ACTIVE_STATE & V_ACTIVE_STATE #(
            h_counter,
            v_counter
        ) begin
            red <= (color_in & (1<<6)) >>6;
            green <= (color_in & (1<<4)) >>4;
            blue <= (color_in & (1<<2)) >>2;
        end
        default #(
            10'd0,
            10'd0
        ) begin
            red <= LOW;
            green <= LOW;
            blue <= LOW;
        end
    endcase

